"""
multi_enemy_kill_order.py

Calculates optimal kill order for multi-enemy fights.
Priority: kill enemies that deal the most damage per turn first,
weighted by how many turns they take to kill.
"""

SCHEMA = {
    "name": "multi_enemy_kill_order",
    "description": "Given a list of enemies with HP and damage-per-turn, returns the optimal kill order to minimize total damage taken.",
    "parameters": {
        "enemies": {
            "type": "list of dicts",
            "each": {
                "name": "str",
                "hp": "int — current HP",
                "dpt": "int — damage per turn this enemy deals",
                "can_block": "bool — whether you can block this enemy's damage"
            }
        },
        "damage_per_energy": "int — average damage you deal per energy spent",
        "energy_per_turn": "int — energy available per turn"
    }
}


def execute(enemies, damage_per_energy, energy_per_turn):
    """
    Returns kill order ranked by (dpt / turns_to_kill) descending.
    Higher score = kill this one first.
    """
    results = []
    for e in enemies:
        hp = max(e["hp"], 1)
        dpt = e.get("dpt", 0)
        # turns to kill = ceil(hp / damage_per_turn)
        damage_per_turn = damage_per_energy * energy_per_turn
        turns_to_kill = (hp + damage_per_turn - 1) // damage_per_turn
        # damage saved by killing early = dpt * turns_to_kill
        # priority score: damage saved per turn invested
        score = dpt / turns_to_kill if turns_to_kill > 0 else 0
        results.append({
            "name": e["name"],
            "hp": hp,
            "dpt": dpt,
            "turns_to_kill": turns_to_kill,
            "priority_score": round(score, 2),
        })

    results.sort(key=lambda x: x["priority_score"], reverse=True)

    return {
        "kill_order": [r["name"] for r in results],
        "details": results,
        "reasoning": (
            f"Focus {results[0]['name']} first — highest damage-per-turn relative to kill cost. "
            f"Killing it saves ~{results[0]['dpt']} damage/turn."
        ) if results else "No enemies provided."
    }


TEST_CASES = [
    {
        "input": {
            "enemies": [
