                {"name": "Leaf Slime (S)", "hp": 14, "dpt": 5},
                {"name": "Twig Slime (M)", "hp": 19, "dpt": 8},
                {"name": "Twig Slime (S)", "hp": 10, "dpt": 4},
            ],
