        },
        "expected_first_kill": "Twig Slime (S)",  # lowest HP, decent dpt — fastest to kill, frees up damage
        "note": "Small enemies with decent dpt should die first to reduce incoming damage quickly"
    },
    {
        "input": {
            "enemies": [
                {"name": "Big Brute", "hp": 80, "dpt": 20},
