    }
]

SCHEMA = {
    "name": "silent_removal_safety_gate",
    "description": (
        "Before removing a card from a Silent deck, checks whether the removal is safe. "
        "Returns a go/no-go decision with the reason. "
        "Pass the full current deck as a list of dicts with 'name' and 'type' (attack/skill/power)."
    ),
    "parameters": {
        "deck": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "type": {"type": "string", "enum": ["attack", "skill", "power"]}
                },
                "required": ["name", "type"]
            },
            "description": "Current deck before removal."
        },
        "card_to_remove": {
            "type": "object",
            "properties": {
                "name": {"type": "string"},
                "type": {"type": "string", "enum": ["attack", "skill", "power"]}
            },
            "required": ["name", "type"],
            "description": "The card being considered for removal."
        }
    }
}

MIN_ATTACK_SOURCES = 5   # below this, deck cannot reliably kill enemies
MIN_DEFENSE_SOURCES = 3  # below this, deck cannot reliably survive

def execute(deck: list, card_to_remove: dict) -> dict:
    """
    Returns:
        safe (bool): whether removal is safe
        reason (str): explanation
        attacks_before (int): attack cards before removal
        attacks_after (int): attack cards after removal
        defends_before (int): defensive cards before removal
        defends_after (int): defensive cards after removal
    """
    attacks_before = sum(1 for c in deck if c["type"] == "attack")
    defends_before = sum(1 for c in deck if c["type"] == "skill")

    removing_attack = card_to_remove["type"] == "attack"
    removing_defend = card_to_remove["type"] == "skill"

    attacks_after = attacks_before - (1 if removing_attack else 0)
    defends_after = defends_before - (1 if removing_defend else 0)

    if attacks_after < MIN_ATTACK_SOURCES:
        return {
            "safe": False,
            "reason": (
                f"UNSAFE: removal would leave only {attacks_after} attack source(s). "
                f"Minimum is {MIN_ATTACK_SOURCES}. Deck cannot reliably kill enemies. "
                "Do NOT remove this card until you add a replacement attack."
            ),
            "attacks_before": attacks_before,
            "attacks_after": attacks_after,
            "defends_before": defends_before,
            "defends_after": defends_after,
        }

    if removing_defend and defends_after < MIN_DEFENSE_SOURCES:
        return {
            "safe": False,
            "reason": (
                f"UNSAFE: removal would leave only {defends_after} defensive skill(s). "
                f"Minimum is {MIN_DEFENSE_SOURCES}. Deck cannot reliably survive early floors."
            ),
            "attacks_before": attacks_before,
            "attacks_after": attacks_after,
            "defends_before": defends_before,
            "defends_after": defends_after,
        }

    return {
        "safe": True,
        "reason": (
            f"Safe to remove. Attacks: {attacks_before}→{attacks_after}, "
            f"Defenses: {defends_before}→{defends_after}. Both above minimums."
        ),
        "attacks_before": attacks_before,
        "attacks_after": attacks_after,
        "defends_before": defends_before,
        "defends_after": defends_after,
    }


