"""
Checks whether it's safe to remove a Strike from a Silent deck by verifying
that enough non-Strike damage sources exist to cover the loss.
"""

SCHEMA = {
    "name": "silent_strike_removal_check",
    "description": (
        "Before removing a Strike from a Silent deck, checks whether the deck "
        "has enough non-Strike damage to compensate. Returns go/no-go with reason."
    ),
    "parameters": {
        "deck": {
            "type": "array",
            "items": {
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "type": {"type": "string", "enum": ["attack", "skill", "power"]},
                    "damage": {"type": "number", "description": "Expected damage per play (0 if non-damaging)"}
                },
                "required": ["name", "type", "damage"]
            },
            "description": "Full current deck as list of cards with name, type, damage."
        },
        "strikes_to_remove": {
            "type": "integer",
            "description": "How many Strikes you want to remove this session.",
            "default": 1
        }
    },
    "required": ["deck"]
}

MIN_NON_STRIKE_DAMAGE_CARDS = 3
MIN_NON_STRIKE_TOTAL_DAMAGE = 18  # 3 × 6 baseline

def execute(deck: list, strikes_to_remove: int = 1) -> dict:
    strikes = [c for c in deck if c["name"].lower().startswith("strike")]
    non_strike_attacks = [
        c for c in deck
        if c["type"] == "attack" and not c["name"].lower().startswith("strike")
    ]

    non_strike_damage_count = len(non_strike_attacks)
    non_strike_total_damage = sum(c["damage"] for c in non_strike_attacks)
    strikes_remaining_after = len(strikes) - strikes_to_remove

    reasons = []
    go = True

    if non_strike_damage_count < MIN_NON_STRIKE_DAMAGE_CARDS:
        go = False
        reasons.append(
            f"Only {non_strike_damage_count} non-Strike attack(s) — need at least {MIN_NON_STRIKE_DAMAGE_CARDS}."
        )

    if non_strike_total_damage < MIN_NON_STRIKE_TOTAL_DAMAGE:
        go = False
        reasons.append(
            f"Non-Strike attacks total only {non_strike_total_damage} damage — need at least {MIN_NON_STRIKE_TOTAL_DAMAGE}."
        )

    if strikes_remaining_after < 0:
        go = False
        reasons.append(f"Can't remove {strikes_to_remove} Strike(s) — only {len(strikes)} in deck.")

    if go:
        reasons.append(
            f"Safe to remove {strikes_to_remove} Strike(s): {non_strike_damage_count} non-Strike attacks "
            f"covering {non_strike_total_damage} damage remain."
        )

    return {
        "go": go,
        "strikes_in_deck": len(strikes),
        "strikes_remaining_after_removal": max(0, strikes_remaining_after),
        "non_strike_attack_count": non_strike_damage_count,
        "non_strike_total_damage": non_strike_total_damage,
        "reason": " | ".join(reasons)
    }


