"""
removal_session_guard.py

Tracks cards removed in the current removal session and blocks
removing so many of one card type that the deck loses a critical function.

SCHEMA describes inputs/outputs for the autonomous agent.
"""

SCHEMA = {
    "name": "removal_session_guard",
    "description": (
        "Given the original deck, the list of cards already removed this session, "
        "and the card proposed for removal, returns GO or NO-GO with a reason. "
        "Prevents removing so many attacks or blocks in one session that the deck "
        "loses a critical function."
    ),
    "input": {
        "original_deck": "list of dicts with 'name' and 'type' (attack/skill/power)",
        "removed_this_session": "list of dicts already removed (same schema)",
        "proposed_removal": "dict with 'name' and 'type'",
    },
    "output": {
        "decision": "GO or NO-GO",
        "reason": "string explanation",
    },
}

MIN_ATTACKS_AFTER = 4   # deck must retain at least this many attack cards
MIN_BLOCKS_AFTER = 2    # deck must retain at least this many block/skill cards
MAX_SAME_TYPE_REMOVED = 2  # never remove more than this many of the same card type in one session


def execute(original_deck, removed_this_session, proposed_removal):
    """
    original_deck: list of {"name": str, "type": str}
    removed_this_session: list of {"name": str, "type": str}
    proposed_removal: {"name": str, "type": str}
    """
    # Build the deck state after all removals including the proposed one
    all_removed = removed_this_session + [proposed_removal]

    # Count remaining by type
    def count_type(deck, card_type):
        return sum(1 for c in deck if c["type"].lower() == card_type.lower())

    # Simulate remaining deck
    remaining = list(original_deck)
    for removal in all_removed:
        for i, card in enumerate(remaining):
            if card["name"].lower() == removal["name"].lower():
                remaining.pop(i)
                break  # remove one copy only

    attacks_left = count_type(remaining, "attack")
    blocks_left = count_type(remaining, "skill")  # skills include block cards

    # Check 1: minimum attacks
    if attacks_left < MIN_ATTACKS_AFTER:
        return {
            "decision": "NO-GO",
            "reason": (
                f"Removing '{proposed_removal['name']}' would leave only {attacks_left} attack(s) "
                f"in the deck (minimum required: {MIN_ATTACKS_AFTER}). "
                f"Do not remove this card."
            ),
        }

    # Check 2: minimum block sources
    if blocks_left < MIN_BLOCKS_AFTER:
        return {
            "decision": "NO-GO",
            "reason": (
                f"Removing '{proposed_removal['name']}' would leave only {blocks_left} skill/block card(s) "
                f"in the deck (minimum required: {MIN_BLOCKS_AFTER}). "
                f"Do not remove this card."
            ),
        }

    # Check 3: don't remove too many of the same card name in one session
    same_name_removed = sum(
        1 for c in all_removed
        if c["name"].lower() == proposed_removal["name"].lower()
    )
    if same_name_removed > MAX_SAME_TYPE_REMOVED:
        return {
            "decision": "NO-GO",
            "reason": (
                f"Already removed {same_name_removed - 1} copy/copies of '{proposed_removal['name']}' "
                f"this session (max allowed: {MAX_SAME_TYPE_REMOVED}). "
                f"Stop removing this card."
            ),
        }

    return {
        "decision": "GO",
        "reason": (
            f"Deck retains {attacks_left} attack(s) and {blocks_left} skill/block card(s) after removal. "
            f"Safe to remove '{proposed_removal['name']}'."
        ),
    }


