SCHEMA = {
    "name": "removal_session_attack_floor",
    "description": "Before removing a card from the deck, checks that the deck will still have enough attack sources after removal. Returns GO or NO-GO with reason.",
    "parameters": {
        "deck": {
            "type": "array",
            "description": "List of dicts with 'name' (str) and 'type' ('attack'|'skill'|'power')",
        },
        "card_to_remove": {
            "type": "object",
            "description": "Dict with 'name' and 'type' of the card being considered for removal",
        },
        "min_attacks": {
            "type": "integer",
            "description": "Minimum attack cards required after removal. Default 5.",
        },
    },
    "required": ["deck", "card_to_remove"],
}

def execute(deck: list, card_to_remove: dict, min_attacks: int = 5) -> dict:
    current_attacks = sum(1 for c in deck if c.get("type") == "attack")
    removing_attack = card_to_remove.get("type") == "attack"
    attacks_after = current_attacks - (1 if removing_attack else 0)

    if attacks_after < min_attacks:
        return {
            "decision": "NO-GO",
            "reason": (
                f"Removing '{card_to_remove['name']}' would leave only {attacks_after} attack(s) "
                f"in the deck (minimum required: {min_attacks}). Keep it until you have more attack replacements."
            ),
            "current_attacks": current_attacks,
            "attacks_after_removal": attacks_after,
            "min_attacks": min_attacks,
        }

    return {
        "decision": "GO",
        "reason": (
            f"Deck will have {attacks_after} attack(s) after removal, above the floor of {min_attacks}."
        ),
        "current_attacks": current_attacks,
        "attacks_after_removal": attacks_after,
        "min_attacks": min_attacks,
    }


