def execute(deck: list, strikes_removed_this_session: int) -> dict:
    MIN_NON_STRIKE_ATTACKS = 4
    MAX_STRIKES_PER_SESSION = 1

    if strikes_removed_this_session >= MAX_STRIKES_PER_SESSION:
        return {
            "decision": "NO-GO",
            "reason": f"Already removed {strikes_removed_this_session} Strike(s) this session. Max 1 per session.",
        }

    non_strike_attacks = [
        c for c in deck
        if c.get("type") == "attack" and "strike" not in c.get("name", "").lower()
    ]

    if len(non_strike_attacks) < MIN_NON_STRIKE_ATTACKS:
        return {
            "decision": "NO-GO",
            "reason": (
                f"Only {len(non_strike_attacks)} non-Strike attack(s) in deck. "
                f"Need at least {MIN_NON_STRIKE_ATTACKS} before removing a Strike."
            ),
        }

    return {
        "decision": "GO",
        "reason": (
            f"{len(non_strike_attacks)} non-Strike attacks present and "
            f"only {strikes_removed_this_session} Strike(s) removed this session."
        ),
    }


