SCHEMA = {
    "description": "Given current HP, incoming damage, current block, energy, and cards in hand, determines whether it is safe to play an attack this turn or whether all energy should go to block. Returns a verdict with reasoning.",
    "parameters": {
        "current_hp": "int — current player HP",
        "incoming_damage": "int — expected damage this turn (after enemy intent)",
        "current_block": "int — block already accumulated this turn",
        "energy_available": "int — energy remaining",
        "hand": "list of dicts with keys: name (str), type (str: attack/skill/power), block_value (int, 0 if not a block card), energy_cost (int)"
    },
    "returns": {
        "can_survive_without_more_block": "bool",
        "can_survive_with_all_block": "bool",
        "max_block_achievable": "int",
        "net_damage_if_all_block": "int",
        "verdict": "str: ATTACK_SAFE | BLOCK_ONLY | LETHAL_EITHER_WAY",
        "reason": "str"
    }
}

def execute(current_hp, incoming_damage, current_block, energy_available, hand):
    # Separate block cards from attack cards, filter by affordable cost
    block_cards = [c for c in hand if c.get("block_value", 0) > 0 and c.get("energy_cost", 1) <= energy_available]
    attack_cards = [c for c in hand if c.get("type") == "attack" and c.get("energy_cost", 1) <= energy_available]

    # Greedily spend all energy on block cards (cheapest first to maximize count)
    block_cards_sorted = sorted(block_cards, key=lambda c: c.get("energy_cost", 1))
    energy_left = energy_available
    total_block = current_block
    for card in block_cards_sorted:
        if card.get("energy_cost", 1) <= energy_left:
            total_block += card.get("block_value", 0)
            energy_left -= card.get("energy_cost", 1)

    max_block_achievable = total_block
    net_damage_all_block = max(0, incoming_damage - max_block_achievable)
    can_survive_with_all_block = (current_hp - net_damage_all_block) > 0

    # Check survival without playing any more block
    net_damage_no_block = max(0, incoming_damage - current_block)
    can_survive_without_more_block = (current_hp - net_damage_no_block) > 0

    # Verdict logic
    if not can_survive_with_all_block:
        verdict = "LETHAL_EITHER_WAY"
        reason = (
            f"Even with all block cards played, you take {net_damage_all_block} damage "
            f"and die ({current_hp} HP). Use a potion or accept death."
        )
    elif can_survive_without_more_block:
        verdict = "ATTACK_SAFE"
        reason = (
            f"Current block ({current_block}) already covers incoming ({incoming_damage}). "
            f"Safe to play attacks."
        )
    else:
        # Need more block — check if we have block cards to play
        if not block_cards:
            verdict = "LETHAL_EITHER_WAY"
            reason = (
                f"No affordable block cards in hand. Will take {net_damage_no_block} damage "
                f"({current_hp} HP). Consider potions."
            )
        else:
            verdict = "BLOCK_ONLY"
            reason = (
                f"Without more block you take {net_damage_no_block} damage and die. "
                f"Play all block cards first (max block: {max_block_achievable}, "
                f"net damage: {net_damage_all_block}). Only attack if energy remains after blocking."
            )

    return {
        "can_survive_without_more_block": can_survive_without_more_block,
        "can_survive_with_all_block": can_survive_with_all_block,
        "max_block_achievable": max_block_achievable,
        "net_damage_if_all_block": net_damage_all_block,
        "verdict": verdict,
        "reason": reason
    }


