        },
        "current_strength": {
            "type": "integer",
            "default": 0,
            "description": "Current Strength value before using the potion."
        },
        "enemy_vulnerable": {
            "type": "boolean",
            "default": False,
            "description": "Whether the enemy is Vulnerable (1.5x damage multiplier)."
        },
        "minimum_bonus_threshold": {
            "type": "integer",
            "default": 15,
            "description": "Minimum bonus damage required to consider the potion worthwhile."
        }
    }
}

def execute(attack_cards, current_strength=0, enemy_vulnerable=False, minimum_bonus_threshold=15):
    FLEX_STRENGTH = 5
    vuln_mult = 1.5 if enemy_vulnerable else 1.0

    total_hits = sum(card["hits"] for card in attack_cards)
    bonus_damage = int(total_hits * FLEX_STRENGTH * vuln_mult)

    # Damage without potion (for context)
    base_total = int(sum(card["hits"] * (card["base_damage"] + current_strength) for card in attack_cards) * vuln_mult)
    boosted_total = int(sum(card["hits"] * (card["base_damage"] + current_strength + FLEX_STRENGTH) for card in attack_cards) * vuln_mult)

    go = bonus_damage >= minimum_bonus_threshold

    return {
        "total_hits_this_turn": total_hits,
        "bonus_damage_from_flex": bonus_damage,
        "damage_without_potion": base_total,
        "damage_with_potion": boosted_total,
        "recommendation": "GO" if go else "NO-GO",
        "reason": (
            f"+{bonus_damage} bonus damage across {total_hits} hit(s). "
            + ("Worth using." if go else f"Below threshold of {minimum_bonus_threshold}. Save the potion.")
        )
    }

