    "name": "block_sufficiency_check",
    "description": (
        "Given current block, a list of block-generating plays planned for this turn, "
        "incoming damage, and current HP, returns whether the plan survives and the exact "
        "deficit or surplus. Use BEFORE finalizing any defensive plan."
    ),
    "parameters": {
        "current_block": {"type": "int", "description": "Block already on the player."},
        "planned_block": {"type": "int", "description": "Total block the planned cards will generate this turn."},
        "incoming_damage": {"type": "int", "description": "Total damage the enemy will deal this turn."},
        "current_hp": {"type": "int", "description": "Player's current HP."},
        "max_hp": {"type": "int", "description": "Player's max HP."}
    }
}

def execute(current_block: int, planned_block: int, incoming_damage: int, current_hp: int, max_hp: int) -> dict:
    total_block = current_block + planned_block
    net_damage = max(0, incoming_damage - total_block)
    hp_after = current_hp - net_damage
    survives = hp_after > 0
    deficit = max(0, incoming_damage - total_block)
    surplus = max(0, total_block - incoming_damage)
    critical = hp_after <= max_hp * 0.20 if survives else False

    if not survives:
        verdict = "FATAL — plan does not survive. Need {} more block or a potion.".format(deficit)
    elif critical:
        verdict = "DANGER — survives but HP drops to {} ({:.0f}% max). Consider potion.".format(
            hp_after, 100 * hp_after / max_hp
        )
    elif deficit > 0:
        # shouldn't happen given logic above but guard anyway
        verdict = "INSUFFICIENT — {} damage leaks through.".format(deficit)
    else:
        verdict = "SAFE — {} block surplus.".format(surplus)

    return {
        "total_block": total_block,
        "incoming_damage": incoming_damage,
        "net_damage_taken": net_damage,
        "hp_after": hp_after,
        "survives": survives,
        "deficit": deficit,
        "surplus": surplus,
        "critical_hp": critical,
        "verdict": verdict
    }

