    "name": "rest_site_heal_vs_upgrade",
    "description": (
        "Given current HP, max HP, floor number, and act number, returns whether to HEAL or UPGRADE "
        "at a rest site. Healing restores 30% of max HP. Returns a GO/NO-GO for healing with the "
        "exact HP numbers and reasoning."
    ),
    "parameters": {
        "current_hp": "int — current HP",
        "max_hp": "int — maximum HP",
        "floor": "int — current floor number",
        "act": "int — current act (1, 2, or 3)",
        "has_key_upgrade": "bool — True if there is a high-impact upgrade available (cost reduction or core power)",
    },
}

def execute(current_hp: int, max_hp: int, floor: int, act: int, has_key_upgrade: bool = False) -> dict:
    hp_pct = current_hp / max_hp
    heal_amount = round(max_hp * 0.30)
    hp_after_heal = min(max_hp, current_hp + heal_amount)

    # How close is the next boss?
    # Act 1 boss ~floor 17, Act 2 boss ~floor 34, Act 3 boss ~floor 51
    boss_floors = {1: 17, 2: 34, 3: 51}
    boss_floor = boss_floors.get(act, 34)
    floors_to_boss = boss_floor - floor

    # Core decision thresholds
    # Below 50%: always heal — upgrade value never exceeds survival
    # 50-70%: heal unless upgrade is high-impact AND boss is far away (>6 floors)
    # Above 70%: upgrade is fine

    if hp_pct < 0.50:
        decision = "HEAL"
        reason = f"HP is critically low ({hp_pct:.0%}). Heal to {hp_after_heal}/{max_hp}. Never upgrade below 50%."
    elif hp_pct < 0.70:
        if has_key_upgrade and floors_to_boss > 6:
            decision = "UPGRADE"
            reason = (
                f"HP is low ({hp_pct:.0%}) but a key upgrade is available and boss is {floors_to_boss} floors away. "
                f"Upgrade is acceptable — but borderline. Consider heal if unsure."
            )
        else:
            decision = "HEAL"
            reason = (
                f"HP is {hp_pct:.0%} ({current_hp}/{max_hp}). Heal restores {heal_amount} HP to {hp_after_heal}. "
                f"Boss is {floors_to_boss} floors away. Healing is safer than upgrading at this HP range."
            )
    else:
        decision = "UPGRADE"
        reason = f"HP is healthy ({hp_pct:.0%}). Upgrade is the better long-term value."

    return {
        "decision": decision,
        "current_hp": current_hp,
        "max_hp": max_hp,
        "hp_pct": round(hp_pct, 3),
        "heal_amount": heal_amount,
        "hp_after_heal": hp_after_heal,
        "floors_to_boss": floors_to_boss,
        "reason": reason,
    }


