"""
poison_lethal_check.py

Given an enemy's current HP and current poison stacks, calculates:
- Whether poison alone will kill the enemy (and on which turn)
- Total damage poison will deal over N turns
- Whether you need to add more poison stacks to guarantee the kill

Poison in STS2 deals X damage at end of turn, then decreases by 1.
Total damage from P stacks = P + (P-1) + ... + 1 = P*(P+1)/2
"""

SCHEMA = {
    "name": "poison_lethal_check",
    "description": (
        "Given enemy HP and current poison stacks, returns whether poison alone "
        "will kill the enemy, which turn it dies, and how many extra stacks are needed "
        "if it won't die. Also handles multi-turn planning with additional stacks added each turn."
    ),
    "parameters": {
        "enemy_hp": "int — current enemy HP",
        "poison_stacks": "int — current poison stacks on the enemy",
        "extra_stacks_per_turn": "int — additional poison stacks added each turn (default 0)",
        "max_turns": "int — how many turns to simulate (default 10)",
    },
}


def execute(enemy_hp: int, poison_stacks: int, extra_stacks_per_turn: int = 0, max_turns: int = 10) -> dict:
    """
    Simulate poison damage over turns.
    Each turn: deal poison damage, then reduce poison by 1, then optionally add more stacks.
    Returns lethal turn (1-indexed) or None, total damage, and stacks needed to guarantee kill this turn.
    """
    if enemy_hp <= 0:
        return {
            "already_dead": True,
            "lethal_turn": 0,
            "total_damage": 0,
            "extra_stacks_needed": 0,
            "simulation": [],
        }

    stacks = poison_stacks
    hp = enemy_hp
    lethal_turn = None
    simulation = []
    total_damage = 0

    for turn in range(1, max_turns + 1):
        if stacks <= 0:
            simulation.append({"turn": turn, "poison_damage": 0, "hp_after": hp, "stacks_after": 0})
            break

        damage = stacks
        hp -= damage
        total_damage += damage
        stacks = max(0, stacks - 1)

        # Add extra stacks after tick (e.g. from a power or card played each turn)
        stacks += extra_stacks_per_turn

        simulation.append({
            "turn": turn,
            "poison_damage": damage,
            "hp_after": hp,
            "stacks_after": stacks,
        })

        if hp <= 0 and lethal_turn is None:
            lethal_turn = turn
            break

    # Calculate how many extra stacks needed RIGHT NOW to kill this turn
    # (i.e. poison_stacks + X >= enemy_hp, so X = max(0, enemy_hp - poison_stacks))
    extra_stacks_needed = max(0, enemy_hp - poison_stacks)

    return {
        "already_dead": False,
        "lethal_turn": lethal_turn,  # None if not lethal within max_turns
        "total_damage_simulated": total_damage,
        "enemy_survives": lethal_turn is None,
        "extra_stacks_needed_for_instant_kill": extra_stacks_needed,
        "simulation": simulation,
    }


