import math

def execute(cards, enemy_hp, enemy_block=0, enemy_vulnerable=False, strength=0, weak_on_player=False):
    total_damage = 0
    card_breakdown = []

    for card in cards:
        dmg = card["base_damage"] + strength
        if dmg < 0:
            dmg = 0
        if weak_on_player:
            dmg = math.floor(dmg * 0.75)
        if enemy_vulnerable:
            dmg = math.floor(dmg * 1.5)
        card_breakdown.append({"name": card["name"], "damage": dmg})
        total_damage += dmg

    damage_after_block = max(0, total_damage - enemy_block)
    remaining_hp = enemy_hp - damage_after_block
    lethal = remaining_hp <= 0
    overkill = max(0, -remaining_hp)

    breakdown_str = ", ".join(f"{c['name']}={c['damage']}" for c in card_breakdown)
    summary = (
        f"Total damage: {total_damage} (vs {enemy_block} block = {damage_after_block} net). "
        f"Enemy HP: {enemy_hp} -> {max(0, remaining_hp)}. "
        f"{'LETHAL' if lethal else 'NOT lethal'}. "
        f"Breakdown: [{breakdown_str}]"
    )

    return {
        "lethal": lethal,
        "total_damage": total_damage,
        "damage_after_block": damage_after_block,
        "remaining_hp": max(0, remaining_hp),
        "overkill": overkill,
        "summary": summary
    }

