def execute(block_cards, dexterity, current_block, incoming_damage, current_hp):
    """
    Computes Dex-adjusted block total and survival outcome.
    Each block card generates (base_block + dexterity) block, minimum 0 per card.
    """
    generated = 0
    card_breakdown = []
    for card in block_cards:
        base = card.get("base_block", 0)
        adjusted = max(0, base + dexterity)
        generated += adjusted
        card_breakdown.append({
            "name": card.get("name", "unknown"),
            "base_block": base,
            "dex_adjustment": dexterity,
            "actual_block": adjusted,
        })

    total_block = current_block + generated
    damage_taken = max(0, incoming_damage - total_block)
    hp_after = current_hp - damage_taken
    survives = hp_after > 0

    deficit = max(0, incoming_damage - total_block)
    surplus = max(0, total_block - incoming_damage)

    return {
        "card_breakdown": card_breakdown,
        "block_generated_by_cards": generated,
        "total_block": total_block,
        "incoming_damage": incoming_damage,
        "damage_taken": damage_taken,
        "hp_after": hp_after,
        "survives": survives,
        "verdict": "SURVIVE" if survives else "LETHAL",
        "deficit": deficit,
        "surplus": surplus,
        "note": (
            f"Dex {dexterity:+d} reduces each block card by {abs(dexterity)}. "
            f"Total block {total_block} vs {incoming_damage} incoming → "
            f"{'survive with ' + str(hp_after) + ' HP' if survives else 'LETHAL by ' + str(abs(hp_after)) + ' HP'}."
        ),
    }


