def execute(enemies: list, current_block: int = 0, current_hp: int = 70) -> dict:
    attacking = [e for e in enemies if e.get("intent") in ("attack", "unknown")]
    non_attacking = [e for e in enemies if e.get("intent") in ("buff", "debuff")]

    total_damage = sum(e.get("damage", 0) for e in attacking)
    net_damage = max(0, total_damage - current_block)
    hp_after = current_hp - net_damage

    safe_to_skip_block = len(attacking) == 0

    return {
        "total_incoming": total_damage,
        "attacking_enemies": [e["name"] for e in attacking],
        "non_attacking_enemies": [e["name"] for e in non_attacking],
        "net_damage_after_block": net_damage,
        "hp_after": hp_after,
        "safe_to_skip_block": safe_to_skip_block,
        "verdict": (
            "SKIP BLOCK — all enemies have non-attack intents this turn."
            if safe_to_skip_block
            else f"MUST BLOCK — {len(attacking)} enemy/enemies attacking for {total_damage} total damage. "
                 f"Net {net_damage} damage after current {current_block} block. HP would be {hp_after}."
        ),
    }


