"""
poison_vs_block_decision.py

Given current poison stacks, enemy HP, turns until death (based on incoming
damage vs current HP/block), tells you whether to keep poisoning or switch to
pure block mode.

SCHEMA and execute() are the required entry points.
"""

SCHEMA = {
    "name": "poison_vs_block_decision",
    "description": (
        "Given current poison stacks on the enemy, enemy HP, player HP, "
        "incoming damage per turn, and current block, returns whether poison "
        "will kill the enemy before the player dies — and whether to keep "
        "stacking poison or switch to pure block. Use BEFORE deciding whether "
        "to play an offensive poison card vs a block card."
    ),
    "parameters": {
        "poison_stacks": {
            "type": "integer",
            "description": "Current poison stacks on the enemy."
        },
        "enemy_hp": {
            "type": "integer",
            "description": "Current enemy HP."
        },
        "player_hp": {
            "type": "integer",
            "description": "Current player HP."
        },
        "incoming_damage_per_turn": {
            "type": "integer",
            "description": "Expected damage the enemy deals each turn (after block)."
        },
        "current_block": {
            "type": "integer",
            "description": "Block the player currently has this turn."
        },
        "block_per_turn": {
            "type": "integer",
            "description": "Block the player can reliably generate each turn going forward."
        },
        "extra_stacks_this_turn": {
            "type": "integer",
            "description": "Additional poison stacks you are considering adding this turn (0 if deciding whether to add any)."
        }
    }
}


def execute(
    poison_stacks: int,
    enemy_hp: int,
    player_hp: int,
    incoming_damage_per_turn: int,
    current_block: int,
    block_per_turn: int,
    extra_stacks_this_turn: int = 0
) -> dict:
    """
    Simulate poison ticking each turn and player taking net damage.
    Poison deals `stacks` damage then decrements by 1 each turn.
    Returns the turn poison kills the enemy, the turn the player dies,
    and a GO/NO-GO on adding more poison vs switching to block.
    """

    # --- simulate poison kill turn ---
    def turns_for_poison_to_kill(stacks, hp):
        """Return turn number (1-indexed) when poison kills, or None if it never does."""
        s = stacks
        remaining = hp
        turn = 0
        while s > 0 and remaining > 0:
            turn += 1
            remaining -= s
            s -= 1
        return turn if remaining <= 0 else None

    # --- simulate player survival ---
    def turns_until_player_dies(php, block_now, block_future, dmg_per_turn):
        """Return turn number when player dies, or None if they survive indefinitely."""
        # Turn 1: existing block absorbs first
        net_turn1 = max(0, dmg_per_turn - block_now)
        php_after_1 = php - net_turn1
        if php_after_1 <= 0:
            return 1
        # Subsequent turns use block_future
        if dmg_per_turn <= block_future:
            return None  # player never dies
        net_per_turn = dmg_per_turn - block_future
        # turns 2+ until death
        turns_remaining = php_after_1 / net_per_turn
        import math
        return 1 + math.ceil(turns_remaining)

    import math

    stacks_with_extra = poison_stacks + extra_stacks_this_turn
    poison_kill_turn = turns_for_poison_to_kill(stacks_with_extra, enemy_hp)
    player_die_turn = turns_until_player_dies(
        player_hp, current_block, block_per_turn, incoming_damage_per_turn
    )

    # Also check without extra stacks
    poison_kill_turn_base = turns_for_poison_to_kill(poison_stacks, enemy_hp)

    # Decision logic
    if player_die_turn is not None and player_die_turn <= 1:
        decision = "NO-GO"
        reason = (
            f"You die THIS turn (turn 1). No offensive play is correct — "
            f"block is the only option."
        )
    elif poison_kill_turn is None:
        decision = "NO-GO"
        reason = (
            f"Poison ({stacks_with_extra} stacks) will never kill the enemy "
            f"({enemy_hp} HP). Switch to block or direct damage."
        )
    elif player_die_turn is not None and poison_kill_turn > player_die_turn:
        decision = "NO-GO"
        reason = (
            f"Poison kills enemy on turn {poison_kill_turn}, but you die on "
            f"turn {player_die_turn}. Switch to block — poison won't save you."
        )
    elif poison_kill_turn_base is not None and (
        player_die_turn is None or poison_kill_turn_base < player_die_turn
    ):
        decision = "NO-GO"
        reason = (
            f"Existing {poison_stacks} stacks already kill the enemy on turn "
            f"{poison_kill_turn_base} (before you die on turn "
            f"{player_die_turn if player_die_turn else 'never'}). "
            f"Don't waste energy adding more — play block instead."
        )
    else:
        decision = "GO"
        reason = (
            f"With {stacks_with_extra} stacks, poison kills on turn "
            f"{poison_kill_turn}. You survive until turn "
            f"{player_die_turn if player_die_turn else 'indefinitely'}. "
            f"Safe to keep poisoning."
        )

    return {
        "decision": decision,
        "reason": reason,
        "poison_kill_turn": poison_kill_turn,
        "player_die_turn": player_die_turn,
        "stacks_evaluated": stacks_with_extra,
        "base_stacks_kill_turn": poison_kill_turn_base,
    }


