def execute(enemies, damage_per_turn_available):
    import math

    if not enemies:
        return {"kill_order": [], "note": "No enemies provided."}

    # Score each enemy: damage_per_turn / turns_to_kill
    # Higher score = kill first (removes most damage fastest)
    def score(e):
        turns_to_kill = math.ceil(e["hp"] / max(damage_per_turn_available, 1))
        dpt = e.get("damage_per_turn", 0)
        # Avoid division by zero; enemies that don't attack get score 0
        return dpt / turns_to_kill if turns_to_kill > 0 else 0

    ranked = sorted(enemies, key=score, reverse=True)

    # Simulate damage taken under this kill order
    total_damage_taken = 0
    remaining = [dict(e) for e in ranked]
    turn = 0
    max_turns = 50  # safety cap

    while any(e["hp"] > 0 for e in remaining) and turn < max_turns:
        turn += 1
        # Player attacks the first living enemy
        for e in remaining:
            if e["hp"] > 0:
                e["hp"] -= damage_per_turn_available
                break
        # All living enemies attack
        total_damage_taken += sum(
            e.get("damage_per_turn", 0) for e in remaining if e["hp"] > 0
        )

    kill_order = [e["name"] for e in ranked]

    return {
        "kill_order": kill_order,
        "estimated_damage_taken": total_damage_taken,
        "turns_to_clear": turn,
        "note": (
            f"Focus {kill_order[0]} first — highest damage-per-turn relative to HP. "
            f"Estimated {total_damage_taken} total damage taken over {turn} turns."
        ),
    }


