def execute(current_hp: int, current_block: int, buffer_active: bool, enemy_attacks: list) -> dict:
    hp = current_hp
    block = current_block
    buffer = buffer_active
    buffer_consumed_by = None
    fatal_attack = None
    total_damage = 0

    for attack in enemy_attacks:
        name = attack.get("name", "Unknown")
        hit_count = attack.get("hit_count", 1)
        dmg_per_hit = attack.get("damage_per_hit", 0)

        for hit_idx in range(hit_count):
            if block >= dmg_per_hit:
                block -= dmg_per_hit
            elif buffer:
                # Buffer absorbs this one unblocked hit entirely
                buffer = False
                buffer_consumed_by = f"{name} hit {hit_idx + 1}"
                # block is NOT reduced — Buffer absorbs the hit, block stays
            else:
                unblocked = dmg_per_hit - block
                block = 0
                hp -= unblocked
                total_damage += unblocked
                if hp <= 0 and fatal_attack is None:
                    fatal_attack = f"{name} hit {hit_idx + 1}"

    survives = hp > 0
    if survives:
        rec = f"GO — survives with {hp} HP remaining."
        if buffer_consumed_by:
            rec += f" Buffer consumed by {buffer_consumed_by}."
    else:
        rec = f"NO-GO — dies to {fatal_attack}. Deficit: {abs(hp)} HP. Need {abs(hp)} more block or HP."

    return {
        "survives": survives,
        "hp_remaining": hp,
        "damage_taken": total_damage,
        "buffer_consumed_by": buffer_consumed_by,
        "fatal_attack": fatal_attack,
        "recommendation": rec,
    }


