        "gold_cost": {"type": "int", "description": "Gold cost of the event branch (0 if none)", "default": 0},
        "hp_cost_is_percentage": {"type": "bool", "description": "If True, hp_cost is a % of current HP (e.g. 50 means lose 50% of current HP)", "default": False},
        "gold_cost_is_percentage": {"type": "bool", "description": "If True, gold_cost is a % of current gold", "default": False},
        "min_survival_hp": {"type": "int", "description": "Minimum HP to consider safe after the event (default 10)", "default": 10},
    }
}

def execute(
    current_hp: int,
    max_hp: int,
    current_gold: int,
    hp_cost: int = 0,
    gold_cost: int = 0,
    hp_cost_is_percentage: bool = False,
    gold_cost_is_percentage: bool = False,
    min_survival_hp: int = 10,
) -> dict:
    # Resolve percentage costs
    actual_hp_cost = int(current_hp * hp_cost / 100) if hp_cost_is_percentage else hp_cost
    actual_gold_cost = int(current_gold * gold_cost / 100) if gold_cost_is_percentage else gold_cost

    hp_after = current_hp - actual_hp_cost
    gold_after = current_gold - actual_gold_cost

    hp_pct_after = round(hp_after / max_hp * 100, 1) if max_hp > 0 else 0

    reasons = []
    go = True

    if hp_after <= 0:
        go = False
        reasons.append(f"LETHAL: HP would drop to {hp_after} (from {current_hp})")
    elif hp_after < min_survival_hp:
        go = False
        reasons.append(f"NEAR-LETHAL: HP would drop to {hp_after} (below safety floor of {min_survival_hp})")
    elif hp_pct_after < 25:
        go = False
        reasons.append(f"DANGEROUS: HP would drop to {hp_after} ({hp_pct_after}% of max) — below 25% threshold")

    if gold_after < 0:
        go = False
        reasons.append(f"CANNOT AFFORD: gold would drop to {gold_after} (from {current_gold})")

    if not reasons:
        reasons.append(f"Survivable: HP {current_hp} -> {hp_after} ({hp_pct_after}% of max), gold {current_gold} -> {gold_after}")

    return {
        "go": go,
        "decision": "GO" if go else "NO-GO",
        "hp_before": current_hp,
        "hp_after": hp_after,
        "hp_pct_after": hp_pct_after,
        "gold_before": current_gold,
        "gold_after": gold_after,
        "actual_hp_cost": actual_hp_cost,
        "actual_gold_cost": actual_gold_cost,
        "reason": " | ".join(reasons),
    }


