def execute(current_hp: int, max_hp: int, floor: int, act: int) -> dict:
    heal_amount = int(max_hp * 0.30)
    hp_after_heal = min(current_hp + heal_amount, max_hp)
    missing_hp = max_hp - current_hp
    hp_pct = current_hp / max_hp

    # Hard thresholds — always heal
    CRITICAL_PCT = 0.40   # below 40% always heal
    DANGER_PCT   = 0.55   # below 55% heal unless very late act and near boss

    # Act-aware boss proximity: last ~5 floors of each act are high-stakes
    boss_proximity = (act == 1 and floor >= 12) or \
                     (act == 2 and floor >= 30) or \
                     (act == 3 and floor >= 48)

    if hp_pct < CRITICAL_PCT:
        decision = "GO"
        reason = (
            f"CRITICAL HP: {current_hp}/{max_hp} ({hp_pct:.0%}). "
            f"Heal restores {heal_amount} HP → {hp_after_heal}/{max_hp}. "
            "Always heal below 40%."
        )
    elif hp_pct < DANGER_PCT and not boss_proximity:
        decision = "GO"
        reason = (
            f"DANGER HP: {current_hp}/{max_hp} ({hp_pct:.0%}). "
            f"Heal restores {heal_amount} HP → {hp_after_heal}/{max_hp}. "
            "Heal below 55% unless near act boss."
        )
    elif hp_pct < DANGER_PCT and boss_proximity:
        decision = "GO"
        reason = (
            f"DANGER HP: {current_hp}/{max_hp} ({hp_pct:.0%}) even near boss. "
            f"Heal restores {heal_amount} HP → {hp_after_heal}/{max_hp}. "
            "Surviving to the boss matters more than one upgrade."
        )
    else:
        decision = "NO-GO"
        reason = (
            f"HP OK: {current_hp}/{max_hp} ({hp_pct:.0%}). "
            f"Heal would give {heal_amount} HP (only {missing_hp} missing). "
            "Upgrade is more valuable."
        )

    return {
        "decision": decision,
        "heal_amount": heal_amount,
        "hp_after_heal": hp_after_heal,
        "hp_pct": round(hp_pct, 3),
        "reason": reason,
    }


