from typing import List, Dict, Any

SCHEMA = {
    "name": "multi_enemy_kill_order_v2",
    "description": (
        "Given a list of enemies with HP and damage_per_turn, returns the optimal kill order "
        "to minimize total damage taken. Prioritizes highest damage-per-HP (threat density) first. "
        "Also returns total damage taken if you follow the recommended order vs worst order."
    ),
    "parameters": {
        "enemies": {
            "type": "array",
            "description": "List of enemies. Each has 'name' (str), 'hp' (int), 'damage_per_turn' (int).",
        },
        "damage_per_turn_available": {
            "type": "integer",
            "description": "How much damage the player can deal per turn total (across all enemies).",
        },
    },
}


def _simulate_order(order: List[Dict], dpt: int) -> int:
    """Simulate total damage taken when killing enemies in the given order."""
    total_damage = 0
    remaining_enemies = list(order)
    turn = 0

    while remaining_enemies:
        # All living enemies deal damage each turn
        total_damage += sum(e["damage_per_turn"] for e in remaining_enemies)
        turn += 1

        # Spend all DPT on the first enemy in order
        target = remaining_enemies[0]
        target = dict(target)  # copy
        target["hp"] -= dpt
        if target["hp"] <= 0:
            remaining_enemies.pop(0)
        else:
            remaining_enemies[0] = target

        if turn > 100:  # safety cap
            break

    return total_damage


def execute(enemies: List[Dict], damage_per_turn_available: int) -> Dict[str, Any]:
    if not enemies:
        return {"error": "No enemies provided."}

    # Sort by threat density: damage_per_turn / hp (highest first)
    recommended_order = sorted(
        enemies,
        key=lambda e: e["damage_per_turn"] / max(e["hp"], 1),
        reverse=True,
    )

    # Also compute worst order (lowest threat density first) for comparison
    worst_order = list(reversed(recommended_order))

    recommended_damage = _simulate_order(
        [dict(e) for e in recommended_order], damage_per_turn_available
    )
    worst_damage = _simulate_order(
        [dict(e) for e in worst_order], damage_per_turn_available
    )

    return {
        "recommended_kill_order": [e["name"] for e in recommended_order],
        "threat_densities": {
            e["name"]: round(e["damage_per_turn"] / max(e["hp"], 1), 3)
            for e in enemies
        },
        "total_damage_recommended_order": recommended_damage,
        "total_damage_worst_order": worst_damage,
        "damage_saved_by_optimal_order": worst_damage - recommended_damage,
        "reasoning": (
            f"Kill {recommended_order[0]['name']} first — highest damage-per-HP ratio. "
            f"Optimal order saves {worst_damage - recommended_damage} HP vs worst order."
        ),
    }


