import math

SCHEMA = {
    "name": "multi_enemy_total_damage",
    "description": (
        "Given a list of enemies with their intents and damage values, plus player state, "
        "returns total incoming damage this turn after Weak modifier, whether the player "
        "survives with current block, and how much extra block is needed. "
        "Use BEFORE deciding how to split energy between offense and defense."
    ),
    "parameters": {
        "enemies": {
            "type": "array",
            "description": (
                "List of dicts with 'name' (str), 'intent' ('attack'|'buff'|'debuff'|'sleep'|'unknown'), "
                "'damage' (int, per hit), 'hits' (int, default 1), 'is_weak' (bool, default False)."
            ),
        },
        "current_block": {"type": "integer", "description": "Block already on the player."},
        "current_hp": {"type": "integer", "description": "Current player HP."},
    },
    "required": ["enemies", "current_block", "current_hp"],
}


def execute(enemies, current_block, current_hp):
    breakdown = []
    total_incoming = 0

    for e in enemies:
        intent = e.get("intent", "unknown")
        if intent != "attack":
            breakdown.append({
                "enemy": e.get("name", "unknown"),
                "intent": intent,
                "damage": 0,
                "note": "not attacking",
            })
            continue

        dmg = e.get("damage", 0)
        hits = e.get("hits", 1)
        is_weak = e.get("is_weak", False)

        raw = dmg * hits
        # Weak reduces enemy damage by 25% (floor per hit)
        if is_weak:
            actual = math.floor(dmg * 0.75) * hits
        else:
            actual = raw

        breakdown.append({
            "enemy": e.get("name", "unknown"),
            "intent": "attack",
            "hits": hits,
            "damage_per_hit": dmg,
            "weak_applied": is_weak,
            "total_damage": actual,
        })
        total_incoming += actual

    damage_after_block = max(0, total_incoming - current_block)
    hp_after = current_hp - damage_after_block
    survives = hp_after > 0
    extra_block_needed = max(0, total_incoming - current_block)

    return {
        "enemy_breakdown": breakdown,
        "total_incoming": total_incoming,
        "current_block": current_block,
        "damage_taken": damage_after_block,
        "hp_after": hp_after,
        "survives": survives,
        "extra_block_needed": extra_block_needed if not survives else 0,
        "verdict": (
            "SURVIVE" if survives
            else f"FATAL — need {extra_block_needed} more block or {damage_after_block - hp_after + 1} less damage"
        ),
    }


