def execute(block_cards, dexterity, frailed, current_block, incoming_damage, current_hp):
    card_block_total = 0
    breakdown = []
    for card in block_cards:
        raw = card["base_block"] + dexterity
        raw = max(0, raw)
        if frailed:
            actual = math.floor(raw * 0.75)
        else:
            actual = raw
        breakdown.append({"card": card["name"], "raw": raw, "actual": actual})
        card_block_total += actual

    total_block = current_block + card_block_total
    damage_taken = max(0, incoming_damage - total_block)
    hp_after = current_hp - damage_taken
    survives = hp_after > 0

    return {
        "breakdown": breakdown,
        "card_block_generated": card_block_total,
        "total_block": total_block,
        "incoming_damage": incoming_damage,
        "damage_taken": damage_taken,
        "hp_after": hp_after,
        "survives": survives,
        "verdict": "SURVIVES" if survives else f"DIES — {abs(hp_after)} HP short",
    }


