SCHEMA = {
    "name": "early_game_survival_gate",
    "description": (
        "Hard gate: given current HP, block cards available (with their block values and energy costs), "
        "total incoming damage this turn, current block already up, current energy, and optional Dexterity, "
        "returns GO (safe to play offense) or NO-GO (must block first) with exact numbers. "
        "Use BEFORE finalizing ANY plan when HP <= 30 or incoming damage >= current HP."
    ),
    "parameters": {
        "current_hp": "int — current player HP",
        "incoming_damage": "int — total damage enemy will deal this turn",
        "current_block": "int — block already on player this turn",
        "energy_available": "int — energy remaining to spend",
        "dexterity": "int — current Dexterity (default 0, can be negative)",
        "block_cards": (
            "list of dicts — each has 'name' (str), 'block_base' (int), 'cost' (int). "
            "Only include cards actually in hand."
        ),
    },
}


def execute(
    current_hp: int,
    incoming_damage: int,
    current_block: int,
    energy_available: int,
    dexterity: int = 0,
    block_cards: list = None,
) -> dict:
    if block_cards is None:
        block_cards = []

    # Sort by block-per-energy efficiency (descending), play as many as energy allows
    # Cards with cost 0 are always free
    affordable = [c for c in block_cards if c["cost"] <= energy_available]

    # Greedy: sort by block value descending (we want max block for available energy)
    affordable_sorted = sorted(affordable, key=lambda c: c["block_base"] + dexterity, reverse=True)

    energy_spent = 0
    block_gained = 0
    cards_played = []

    for card in affordable_sorted:
        if energy_spent + card["cost"] <= energy_available:
            raw = card["block_base"] + dexterity
            actual = max(0, raw)  # block can't go negative
            block_gained += actual
            energy_spent += card["cost"]
            cards_played.append({"name": card["name"], "block": actual, "cost": card["cost"]})

    total_block = current_block + block_gained
    damage_taken = max(0, incoming_damage - total_block)
    hp_after = current_hp - damage_taken
    survives = hp_after > 0
    deficit = max(0, incoming_damage - total_block)

    decision = "GO" if survives else "NO-GO"
    if survives and deficit == 0:
        reason = f"Full block: {total_block} block covers {incoming_damage} damage. {hp_after} HP remaining."
    elif survives and deficit > 0:
        reason = (
            f"Partial block: {total_block} block vs {incoming_damage} damage. "
            f"Takes {deficit} damage, survives at {hp_after} HP. Consider more block if available."
        )
    else:
        reason = (
            f"LETHAL: {total_block} block vs {incoming_damage} damage. "
            f"Takes {deficit} damage, dies at {hp_after} HP. Must find more block or the run ends."
        )

    return {
        "decision": decision,
        "survives": survives,
        "total_block": total_block,
        "block_gained_this_turn": block_gained,
        "damage_taken": damage_taken,
        "hp_after": hp_after,
        "cards_played": cards_played,
        "energy_spent": energy_spent,
        "reason": reason,
    }


