def execute(attack_cards, current_strength=0, enemy_vulnerable=False, enemy_weak=False, enemy_block=0):
    import math

    total_damage = 0
    remaining_block = enemy_block

    for card in attack_cards:
        base = card.get("base_damage", 0)
        hits = card.get("hits", 1)

        for _ in range(hits):
            # Apply Strength
            damage = base + current_strength

            # Apply Weak (0.75x per hit, floor)
            if enemy_weak:
                damage = math.floor(damage * 0.75)

            # Apply Vulnerable (1.5x per hit, floor)
            if enemy_vulnerable:
                damage = math.floor(damage * 1.5)

            # Apply block
            if remaining_block > 0:
                blocked = min(damage, remaining_block)
                damage -= blocked
                remaining_block -= blocked

            total_damage += damage

    return {
        "total_damage": total_damage,
        "overkill_block": remaining_block,
        "summary": f"{total_damage} damage (block absorbed {enemy_block - remaining_block})"
    }

