            "required": True
        }
    }
}

def execute(current_deck, cards_to_remove, floor):
    attacks = [c for c in current_deck if c.get("type") == "attack"]
    skills = [c for c in current_deck if c.get("type") == "skill"]

    attacks_removed = sum(1 for name in cards_to_remove if any(c["name"] == name and c["type"] == "attack" for c in current_deck))
    skills_removed = sum(1 for name in cards_to_remove if any(c["name"] == name and c["type"] == "skill" for c in current_deck))

    final_attacks = len(attacks) - attacks_removed
    final_skills = len(skills) - skills_removed

    if floor <= 10 and final_attacks < 4:
        return {"decision": "NO-GO", "reason": f"Only {final_attacks} attacks left in early Act 1 - need at least 4 to kill enemies"}

    if floor <= 10 and final_skills < 3:
        return {"decision": "NO-GO", "reason": f"Only {final_skills} skills left - need block cards to survive"}

    return {"decision": "GO", "reason": f"Safe: {final_attacks} attacks, {final_skills} skills remaining"}

