"""
Multi-enemy attrition check: Given enemy states, player state, and approximate
offense/defense output per turn, calculates whether the player is winning or
losing the damage race. Flags ATTRITION_CRITICAL when blocking alone leads to death.
"""

SCHEMA = {
    "description": "In a multi-enemy fight, calculates whether the player is winning or losing the attrition war. Returns turns_to_die (blocking every turn), turns_to_first_kill (if focusing fire), and a verdict: OFFENSE_CRITICAL (must stop turtling) or OK.",
    "properties": {
        "player_hp": {
            "type": "integer",
            "description": "Current player HP"
        },
        "block_per_turn": {
            "type": "integer",
            "description": "Average block the player generates per turn (e.g. 15-20 for 3 Defends)"
        },
        "damage_per_turn": {
            "type": "integer",
            "description": "Average damage the player deals per turn if going offense instead of full block"
        },
        "enemies": {
            "type": "array",
            "description": "List of enemies with 'name' (str), 'hp' (int), 'damage_per_turn' (int average)",
            "items": {"type": "object"}
        }
    },
    "required": ["player_hp", "block_per_turn", "damage_per_turn", "enemies"]
}


def execute(player_hp, block_per_turn, damage_per_turn, enemies):
    # Calculate total enemy damage per turn
    total_enemy_dpt = sum(e.get("damage_per_turn", 0) for e in enemies)

    # Calculate chip damage per turn (damage that gets through block)
    chip_per_turn = max(0, total_enemy_dpt - block_per_turn)

    # Turns to die if purely blocking
    if chip_per_turn > 0:
        turns_to_die = player_hp // chip_per_turn
    else:
        turns_to_die = 999  # Effectively infinite if block covers all damage

    # Find the weakest enemy (fastest to kill via focus fire)
    # When focusing fire, assume we split energy: ~60% offense, ~40% block
    # So we deal about damage_per_turn worth of damage while taking more chip
    enemies_sorted = sorted(enemies, key=lambda e: e["hp"])
    weakest = enemies_sorted[0]

    turns_to_first_kill = max(1, -(-weakest["hp"] // damage_per_turn))  # Ceiling division

    # After first kill, what's the new total enemy DPT?
    remaining_dpt = total_enemy_dpt - weakest.get("damage_per_turn", 0)

    # During focus fire, we block less (say 50-60% of normal block)
    reduced_block = block_per_turn * 6 // 10  # 60% block while attacking
    chip_during_offense = max(0, total_enemy_dpt - reduced_block)

    # HP cost of focusing fire for turns_to_first_kill turns
    hp_cost_to_kill = chip_during_offense * turns_to_first_kill

    # After first kill, new chip rate
    chip_after_kill = max(0, remaining_dpt - block_per_turn)

    # Is focus fire survivable?
    hp_after_first_kill = player_hp - hp_cost_to_kill
    focus_fire_survivable = hp_after_first_kill > 0

    # Verdict
    if turns_to_die <= 3:
        verdict = "OFFENSE_CRITICAL"
        reason = f"Only {turns_to_die} turns to live while turtling. MUST deal damage NOW or die."
    elif turns_to_die <= turns_to_first_kill + 2:
        verdict = "OFFENSE_CRITICAL"
        reason = f"Turtling dies in {turns_to_die} turns. First kill takes {turns_to_first_kill} turns. No margin — must offense."
    elif chip_per_turn > 0 and turns_to_die < 999:
        verdict = "OFFENSE_RECOMMENDED"
        reason = f"Taking {chip_per_turn} chip/turn through block. Will die in {turns_to_die} turns. Start killing enemies."
    else:
        verdict = "OK"
        reason = f"Block covers incoming damage. But still prioritize killing to end fight faster."

    # Recommended target
    # Efficiency = damage_per_turn / hp (higher = faster to kill, reduces DPT sooner)
    best_target = max(enemies, key=lambda e: e.get("damage_per_turn", 0) / max(1, e["hp"]))

    return {
        "verdict": verdict,
        "reason": reason,
        "total_enemy_dpt": total_enemy_dpt,
        "chip_per_turn_blocking": chip_per_turn,
        "turns_to_die_turtling": min(turns_to_die, 999),
        "weakest_enemy": weakest["name"],
        "turns_to_first_kill": turns_to_first_kill,
        "hp_cost_to_kill_first": hp_cost_to_kill,
        "focus_fire_survivable": focus_fire_survivable,
        "recommended_target": f"{best_target['name']} (HP={best_target['hp']}, DPT={best_target.get('damage_per_turn', 0)})",
        "enemy_dpt_after_first_kill": remaining_dpt
    }


