}

def execute(player_hp, block_per_turn, damage_per_turn, enemies):
    """Calculate attrition war status in multi-enemy fights."""
    # Total incoming damage per turn
    total_enemy_dpt = sum(e.get("damage_per_turn", 0) for e in enemies)

    # Net damage taken per turn (after block)
    net_damage_per_turn = max(0, total_enemy_dpt - block_per_turn)

    # Turns until player dies (if only blocking)
    if net_damage_per_turn <= 0:
        turns_to_die = 999  # Player isn't taking damage
    else:
        turns_to_die = player_hp // net_damage_per_turn
        if player_hp % net_damage_per_turn > 0:
            turns_to_die += 1  # Ceiling division for survival

    # Find optimal first kill target (lowest HP enemy that deals damage)
    attacking_enemies = [e for e in enemies if e.get("damage_per_turn", 0) > 0]
    if not attacking_enemies:
        attacking_enemies = enemies  # If none attack, still need to kill them

    # Sort by HP (kill weakest first to reduce incoming damage fastest)
    sorted_by_efficiency = sorted(
        attacking_enemies,
        key=lambda e: e["hp"] / max(e.get("damage_per_turn", 1), 1)
    )

    # Turns to kill the most efficient target
    if sorted_by_efficiency:
        first_target = sorted_by_efficiency[0]
        if damage_per_turn <= 0:
            turns_to_first_kill = 999
        else:
            turns_to_first_kill = first_target["hp"] // damage_per_turn
            if first_target["hp"] % damage_per_turn > 0:
                turns_to_first_kill += 1
    else:
        turns_to_first_kill = 0

    # Simulate focus-fire strategy: kill enemies one by one
    remaining_enemies = sorted(enemies, key=lambda e: e["hp"] / max(e.get("damage_per_turn", 1), 1))
    sim_hp = player_hp
    sim_turn = 0
    total_damage_taken = 0
    alive_enemies = list(remaining_enemies)
    kills_before_death = 0

    while sim_hp > 0 and alive_enemies:
        sim_turn += 1
        # Take damage from all alive enemies
        turn_damage = sum(e.get("damage_per_turn", 0) for e in alive_enemies)
        net_turn_damage = max(0, turn_damage - block_per_turn)
        sim_hp -= net_turn_damage
        total_damage_taken += net_turn_damage

        if sim_hp <= 0:
            break

        # Deal damage to first target
        alive_enemies[0]["hp"] = alive_enemies[0].get("hp", 0) - damage_per_turn
        if alive_enemies[0]["hp"] <= 0:
            kills_before_death += 1
            alive_enemies.pop(0)

    player_wins = len(alive_enemies) == 0 and sim_hp > 0

    # Verdict
    if turns_to_die <= 2 and not player_wins:
        verdict = "OFFENSE_CRITICAL"
        reason = f"You die in ~{turns_to_die} turns of pure blocking. Must kill something NOW."
    elif turns_to_die <= turns_to_first_kill and not player_wins:
        verdict = "OFFENSE_CRITICAL" 
        reason = f"You die in {turns_to_die} turns but first kill takes {turns_to_first_kill} turns. Must prioritize damage."
    elif player_wins:
        verdict = "DEFENSE_OK"
        reason = f"Focus-fire wins in {sim_turn} turns with {sim_hp} HP remaining. Kill order: {[e['name'] for e in sorted_by_efficiency]}"
    else:
        verdict = "OFFENSE_CRITICAL"
        reason = f"Cannot win by attrition. Kill {kills_before_death}/{len(enemies)} enemies before dying on turn {sim_turn}."

    first_target_name = sorted_by_efficiency[0]["name"] if sorted_by_efficiency else "none"

    return {
        "total_enemy_dpt": total_enemy_dpt,
        "net_damage_per_turn": net_damage_per_turn,
        "turns_to_die": turns_to_die,
        "turns_to_first_kill": turns_to_first_kill,
        "first_kill_target": first_target_name,
        "verdict": verdict,
        "reason": reason,
