"""
Multi-enemy attrition calculator v2.
Given enemies with HP and damage, plus player stats, determines whether the player
is winning or losing the attrition war and recommends offense vs defense priority.
"""

SCHEMA = {
    "description": "In a multi-enemy fight, calculates whether the player is winning or losing the attrition war. Returns turns_to_die (if just blocking), turns_to_first_kill (if focusing fire on best target), optimal focus target, and a verdict. Use at the START of multi-enemy combats and when deciding offense vs defense.",
    "properties": {
        "enemies": {
            "description": "List of enemies. Each has 'name' (str), 'hp' (int), 'damage_per_turn' (int).",
            "items": {"type": "object"},
            "type": "array"
        },
        "player_hp": {
            "description": "Current player HP.",
            "type": "integer"
        },
        "player_block_per_turn": {
            "description": "Approximate block the player generates per turn (e.g., 10-15 for 2 Defends).",
            "type": "integer"
        },
        "player_damage_per_turn": {
            "description": "Approximate damage the player deals per turn when going offensive.",
            "type": "integer"
        },
        "poison_on_enemies": {
            "description": "Optional: dict of enemy_name -> current poison stacks. Poison ticks down each turn dealing damage.",
            "type": "object"
        }
    },
    "required": ["enemies", "player_hp", "player_block_per_turn", "player_damage_per_turn"]
}

import math

def execute(enemies, player_hp, player_block_per_turn, player_damage_per_turn, poison_on_enemies=None):
    if poison_on_enemies is None:
        poison_on_enemies = {}

    total_enemy_damage = sum(e["damage_per_turn"] for e in enemies)
    net_damage_per_turn = max(0, total_enemy_damage - player_block_per_turn)

    # Turns to die if just blocking (no kills)
    if net_damage_per_turn <= 0:
        turns_to_die = 999  # Effectively infinite
    else:
        turns_to_die = math.ceil(player_hp / net_damage_per_turn)

    # For each enemy, calculate turns to kill if focusing fire
    # Account for poison damage (poison ticks at start of enemy turn, decrements by 1 each turn)
    focus_options = []
    for e in enemies:
        name = e["name"]
        hp = e["hp"]
        poison = poison_on_enemies.get(name, 0)
        dmg_per_turn = e["damage_per_turn"]

        # Simulate turns to kill with focus fire + poison
        remaining_hp = hp
        turns = 0
        current_poison = poison
        while remaining_hp > 0 and turns < 50:
            turns += 1
            # Poison ticks first (at start of enemy turn / end of our turn)
            if current_poison > 0:
                remaining_hp -= current_poison
                current_poison -= 1
            # Player damage
            remaining_hp -= player_damage_per_turn

        if remaining_hp <= 0:
            # Damage removed from total once this enemy dies
            damage_removed = dmg_per_turn
            # Efficiency = damage removed per turn spent
            efficiency = damage_removed / max(turns, 1)
            focus_options.append({
                "name": name,
                "turns_to_kill": turns,
                "damage_removed": damage_removed,
                "efficiency": round(efficiency, 2),
                "remaining_hp": max(0, hp)
            })
        else:
            focus_options.append({
                "name": name,
                "turns_to_kill": 50,
                "damage_removed": dmg_per_turn,
                "efficiency": 0,
                "remaining_hp": hp
            })

    # Best target = highest efficiency (most damage removed per turn invested)
    # Tie-break: fewest turns to kill
    focus_options.sort(key=lambda x: (-x["efficiency"], x["turns_to_kill"]))
    best_target = focus_options[0] if focus_options else None

    # Calculate damage taken while killing the first target
    if best_target:
        damage_taken_during_kill = net_damage_per_turn * best_target["turns_to_kill"]
        survives_first_kill = player_hp > damage_taken_during_kill
    else:
        damage_taken_during_kill = 0
        survives_first_kill = True

    # Verdict
    if turns_to_die <= 2:
        verdict = "CRITICAL — You die in {0} turns. Must kill something NOW or find massive block.".format(turns_to_die)
    elif best_target and not survives_first_kill:
        verdict = "OFFENSE_CRITICAL — You die before killing {0} ({1} turns to kill, {2} turns to die). Consider: can you kill faster? Use potions? AoE?".format(
            best_target["name"], best_target["turns_to_kill"], turns_to_die)
    elif best_target and best_target["turns_to_kill"] >= turns_to_die - 1:
        verdict = "OFFENSE_URGENT — Barely survive killing {0}. Prioritize damage, minimal blocking.".format(best_target["name"])
    elif net_damage_per_turn <= 0:
        verdict = "DEFENSE_OK — Block exceeds damage. Can turtle and set up."
    else:
        verdict = "MANAGEABLE — Can survive {0} turns, first kill in {1}. Balance offense/defense.".format(
            turns_to_die, best_target["turns_to_kill"] if best_target else "?")

    result = {
        "total_enemy_damage_per_turn": total_enemy_damage,
        "net_damage_per_turn_after_block": net_damage_per_turn,
        "turns_to_die": turns_to_die,
        "focus_targets": [{"name": f["name"], "turns_to_kill": f["turns_to_kill"], 
                          "efficiency": f["efficiency"]} for f in focus_options],
        "recommended_target": best_target["name"] if best_target else None,
        "damage_taken_killing_first_target": damage_taken_during_kill,
        "survives_first_kill": survives_first_kill,
        "verdict": verdict
    }

    return result


