            "description": "Current player HP.",
            "type": "integer"
        },
        "player_block_per_turn": {
            "description": "Approximate block the player generates per turn (e.g., 13 for 2 Defends + Dex).",
            "type": "integer"
        },
        "player_damage_per_turn": {
            "description": "Approximate damage the player deals per turn when going offensive.",
            "type": "integer"
        },
        "poison_on_enemies": {
            "description": "Optional: dict of enemy_name -> current poison stacks.",
            "type": "object"
        }
    },
    "required": ["enemies", "player_hp", "player_block_per_turn", "player_damage_per_turn"]
}

import math

def execute(enemies, player_hp, player_block_per_turn, player_damage_per_turn, poison_on_enemies=None):
    if poison_on_enemies is None:
        poison_on_enemies = {}

    total_enemy_damage = sum(e["damage_per_turn"] for e in enemies)
    net_damage = max(0, total_enemy_damage - player_block_per_turn)

    if net_damage <= 0:
        turns_to_die = 999
    else:
        turns_to_die = math.ceil(player_hp / net_damage)

    focus_options = []
    for e in enemies:
        name = e["name"]
        hp = e["hp"]
        poison = poison_on_enemies.get(name, 0)
        dmg = e["damage_per_turn"]

        remaining = hp
        turns = 0
        p = poison
        while remaining > 0 and turns < 50:
            turns += 1
            if p > 0:
                remaining -= p
                p -= 1
            remaining -= player_damage_per_turn

        eff = dmg / max(turns, 1)
        focus_options.append({
            "name": name,
            "turns_to_kill": min(turns, 50),
            "damage_removed": dmg,
            "efficiency": round(eff, 2)
        })

    focus_options.sort(key=lambda x: (-x["efficiency"], x["turns_to_kill"]))
    best = focus_options[0] if focus_options else None

    damage_during_kill = net_damage * best["turns_to_kill"] if best else 0
    survives = player_hp > damage_during_kill

    if turns_to_die <= 2:
        verdict = "CRITICAL: Die in {} turns! Must kill NOW or find massive block/potion.".format(turns_to_die)
    elif best and not survives:
        verdict = "OFFENSE_CRITICAL: Die before killing {} (kill={} turns, die={} turns). Use potions/AoE.".format(
            best["name"], best["turns_to_kill"], turns_to_die)
    elif best and best["turns_to_kill"] >= turns_to_die - 1:
        verdict = "OFFENSE_URGENT: Barely survive killing {}. Prioritize damage.".format(best["name"])
    elif net_damage <= 0:
        verdict = "DEFENSE_OK: Block >= damage. Safe to set up."
    else:
        verdict = "MANAGEABLE: Survive {} turns, first kill in {}. Balance offense/defense.".format(
            turns_to_die, best["turns_to_kill"] if best else "?")

    return {
        "total_enemy_damage": total_enemy_damage,
        "net_damage_after_block": net_damage,
        "turns_to_die": turns_to_die,
        "focus_targets": focus_options,
        "recommended_target": best["name"] if best else None,
        "hp_cost_of_first_kill": damage_during_kill,
        "survives_first_kill": survives,
        "verdict": verdict
    }


