"""
Multi-enemy attrition calculator v3 — REPLACES the three broken parameterless versions.
Given player state and enemy list, determines whether the player is winning or losing
the damage race and recommends offense vs defense priority.
"""

SCHEMA = {
    "description": "In a multi-enemy fight, calculates whether the player is winning or losing the attrition war. Given player HP, block capacity, damage output, and enemy stats, returns turns_to_die, turns_to_first_kill, optimal focus target, and a verdict. Use at the START of multi-enemy combats and when deciding offense vs defense split.",
    "properties": {
        "player_hp": {
            "type": "integer",
            "description": "Player's current HP."
        },
        "player_block_per_turn": {
            "type": "integer",
            "description": "Approximate block the player can generate per turn (e.g. 10-15 for typical Silent)."
        },
        "player_damage_per_turn": {
            "type": "integer",
            "description": "Approximate damage the player can deal per turn to a single target."
        },
        "enemies": {
            "type": "array",
            "description": "List of enemies. Each has 'name' (str), 'hp' (int), 'damage_per_turn' (int average), and optionally 'poison' (int, current poison stacks).",
            "items": {"type": "object"}
        }
    },
    "required": ["player_hp", "player_block_per_turn", "player_damage_per_turn", "enemies"]
}


def _simulate_poison_damage(hp, poison_stacks, max_turns=20):
    """Returns total damage poison deals over max_turns, and turn of death (or -1)."""
    total_poison_dmg = 0
    p = poison_stacks
    for t in range(1, max_turns + 1):
        if p <= 0:
            break
        total_poison_dmg += p
        hp -= p
        if hp <= 0:
            return total_poison_dmg, t
        p -= 1
    return total_poison_dmg, -1  # -1 means not killed by poison alone


def execute(player_hp, player_block_per_turn, player_damage_per_turn, enemies):
    results = {}

    # Calculate total incoming damage per turn
    total_enemy_dpt = sum(e.get("damage_per_turn", 0) for e in enemies)

    # Net damage taken per turn (after blocking)
    net_damage_per_turn = max(0, total_enemy_dpt - player_block_per_turn)

    # Turns to die if we only block
    if net_damage_per_turn > 0:
        turns_to_die = player_hp // net_damage_per_turn
    else:
        turns_to_die = 999  # Effectively infinite if block >= incoming

    results["total_enemy_damage_per_turn"] = total_enemy_dpt
    results["net_damage_per_turn"] = net_damage_per_turn
    results["turns_to_die_blocking"] = turns_to_die

    # For each enemy, calculate turns to kill (focus fire) and factor in poison
    enemy_analysis = []
    for e in enemies:
        name = e["name"]
        hp = e["hp"]
        dpt = e.get("damage_per_turn", 0)
        poison = e.get("poison", 0)

        # Poison damage simulation
        poison_dmg_total, poison_kill_turn = _simulate_poison_damage(hp, poison)

        # Effective HP after poison (how much player needs to deal)
        effective_hp = max(0, hp - poison_dmg_total)

        # Turns to kill with focus fire (player damage + poison)
        if player_damage_per_turn > 0:
            # Simulate turn by turn with both poison and player damage
            sim_hp = hp
            sim_poison = poison
            kill_turn = -1
            for t in range(1, 30):
                # Poison ticks at start of enemy turn
                if sim_poison > 0:
                    sim_hp -= sim_poison
                    sim_poison -= 1
                if sim_hp <= 0:
                    kill_turn = t
                    break
                # Player deals damage
                sim_hp -= player_damage_per_turn
                if sim_hp <= 0:
                    kill_turn = t
                    break
            turns_to_kill = kill_turn if kill_turn > 0 else 30
        else:
            turns_to_kill = poison_kill_turn if poison_kill_turn > 0 else 999

        # Danger score: damage per turn / turns to kill (higher = more dangerous, kill first)
        danger_score = dpt / max(1, turns_to_kill)

        enemy_analysis.append({
            "name": name,
            "hp": hp,
            "damage_per_turn": dpt,
            "poison": poison,
            "poison_kill_turn": poison_kill_turn,
            "effective_hp_after_poison": effective_hp,
            "turns_to_kill_focus": turns_to_kill,
            "danger_score": round(danger_score, 2)
        })

    # Sort by danger score (highest first = kill first)
    enemy_analysis.sort(key=lambda x: x["danger_score"], reverse=True)
    results["enemies"] = enemy_analysis

    # Optimal focus target
    focus_target = enemy_analysis[0]["name"] if enemy_analysis else "none"
    results["focus_target"] = focus_target

    # Turns to first kill (focusing optimal target)
    turns_to_first_kill = enemy_analysis[0]["turns_to_kill_focus"] if enemy_analysis else 999
    results["turns_to_first_kill"] = turns_to_first_kill

    # Verdict
    if turns_to_die <= 1:
        verdict = "CRITICAL"
        advice = "You die next turn. Full defense or use potions."
    elif turns_to_die <= turns_to_first_kill:
        verdict = "OFFENSE_CRITICAL"
        advice = f"You die in {turns_to_die} turns but need {turns_to_first_kill} to kill {focus_target}. Must increase offense or use potions/AoE. Consider switching to a squishier target."
    elif turns_to_die <= turns_to_first_kill + 1:
        verdict = "OFFENSE_URGENT"
        advice = f"Tight race. Kill {focus_target} in {turns_to_first_kill} turns, you die in {turns_to_die}. Prioritize offense, minimal block."
    elif turns_to_die <= turns_to_first_kill + 3:
        verdict = "MANAGEABLE"
        advice = f"Winnable but stay aggressive. Focus {focus_target} ({turns_to_first_kill} turns to kill)."
    else:
        verdict = "DEFENSE_OK"
        advice = f"Comfortable margin. {turns_to_die} turns to die vs {turns_to_first_kill} to first kill."

    # Check if any enemy dies to poison alone
    for ea in enemy_analysis:
        if ea["poison_kill_turn"] > 0 and ea["poison_kill_turn"] <= turns_to_die:
            advice += f" NOTE: {ea['name']} dies to poison alone on turn {ea['poison_kill_turn']} — consider focusing the OTHER enemy."

    results["verdict"] = verdict
    results["advice"] = advice

    return results


