def execute(player_hp, block_per_turn, damage_per_turn, enemies):
    """Calculate attrition war status in a multi-enemy fight."""

    if not enemies:
        return {"error": "No enemies provided"}

    if player_hp <= 0:
        return {"verdict": "DEAD", "message": "Player is already dead"}

    # Calculate total incoming damage per turn
    total_enemy_dpt = sum(e.get("damage_per_turn", 0) for e in enemies)

    # Net damage taken per turn when fully blocking
    net_damage_per_turn = max(0, total_enemy_dpt - block_per_turn)

    # Turns to die if only blocking (no kills)
    if net_damage_per_turn > 0:
        turns_to_die = player_hp // net_damage_per_turn
        if player_hp % net_damage_per_turn > 0:
            turns_to_die += 1  # partial turn counts
    else:
        turns_to_die = 999  # effectively infinite, block covers all damage

    # For each enemy, calculate turns to kill if focused
    # Account for poison damage (poison ticks at start of enemy turn, decrements by 1 each turn)
    kill_analysis = []
    for e in enemies:
        name = e.get("name", "Unknown")
        hp = e.get("hp", 1)
        dpt = e.get("damage_per_turn", 0)
        poison = e.get("poison", 0)

        # Simulate focusing this enemy with player damage + poison
        remaining_hp = hp
        turns = 0
        current_poison = poison

        while remaining_hp > 0 and turns < 50:
            turns += 1
            # Poison ticks at start of turn
            if current_poison > 0:
                remaining_hp -= current_poison
                current_poison = max(0, current_poison - 1)
            # Player damage
            remaining_hp -= damage_per_turn

        # Efficiency = how much total enemy damage we prevent per turn spent killing
        efficiency = dpt / max(1, turns)  # damage removed per turn invested

        kill_analysis.append({
            "name": name,
            "hp": hp,
            "damage_per_turn": dpt,
            "poison": poison,
            "turns_to_kill": turns,
            "damage_prevented_per_turn_invested": round(efficiency, 2)
        })

    # Sort by efficiency (highest first) = optimal kill order
    kill_analysis.sort(key=lambda x: -x["damage_prevented_per_turn_invested"])

    optimal_target = kill_analysis[0]
    turns_to_first_kill = optimal_target["turns_to_kill"]

    # Simulate the optimal kill sequence
    # While killing the first target, how much damage do we take?
    # We assume we split energy: some offense, some defense
    # Simplified: during kill phase, we take full enemy damage (offense-focused)
    damage_during_first_kill = total_enemy_dpt * turns_to_first_kill
    hp_after_first_kill = player_hp - max(0, damage_during_first_kill - block_per_turn * turns_to_first_kill)

    # Determine verdict
    if turns_to_die <= 1:
        verdict = "CRITICAL"
        message = f"DYING NEXT TURN. Net damage/turn={net_damage_per_turn}, HP={player_hp}. Must block or use potions."
    elif turns_to_first_kill >= turns_to_die:
        verdict = "OFFENSE_CRITICAL"
        message = (
            f"Cannot kill any enemy before dying! Turns to die={turns_to_die}, "
            f"fastest kill={turns_to_first_kill} turns ({optimal_target['name']}). "
            f"Must use AoE, potions, or prioritize killing the weakest enemy."
        )
    elif turns_to_first_kill >= turns_to_die - 1:
        verdict = "OFFENSE_URGENT"
        message = (
            f"Barely surviving to first kill. Turns to die={turns_to_die}, "
            f"first kill in {turns_to_first_kill} turns ({optimal_target['name']}). "
            f"Focus ALL offense on {optimal_target['name']}. No wasted damage."
        )
    elif hp_after_first_kill <= player_hp * 0.3:
        verdict = "MANAGEABLE"
        message = (
            f"Can kill {optimal_target['name']} in {turns_to_first_kill} turns "
            f"but will be low HP ({hp_after_first_kill}). Balance offense and defense."
        )
    else:
        verdict = "DEFENSE_OK"
        message = (
            f"Attrition war is winnable. Kill {optimal_target['name']} in {turns_to_first_kill} turns, "
            f"then mop up. HP after first kill ≈ {hp_after_first_kill}."
        )

    return {
        "verdict": verdict,
        "message": message,
        "turns_to_die_blocking": turns_to_die,
        "total_enemy_dpt": total_enemy_dpt,
        "net_damage_per_turn": net_damage_per_turn,
        "optimal_focus_target": optimal_target["name"],
        "turns_to_first_kill": turns_to_first_kill,
        "kill_order": [
            {"name": k["name"], "turns": k["turns_to_kill"], "efficiency": k["damage_prevented_per_turn_invested"]}
            for k in kill_analysis
        ],
        "hp_after_first_kill_estimate": max(0, hp_after_first_kill)
    }


