def execute(player_hp, block_per_turn, damage_per_turn, enemies):
    # Validate inputs
    if not enemies:
        return {"error": "No enemies provided"}
    if player_hp <= 0:
        return {"verdict": "CRITICAL", "reason": "Player is already dead"}

    # Parse enemies with defaults
    parsed = []
    for e in enemies:
        parsed.append({
            "name": e.get("name", "Unknown"),
            "hp": e.get("hp", 1),
            "damage_per_turn": e.get("damage_per_turn", 0),
            "poison": e.get("poison", 0)
        })

    # Calculate total incoming damage per turn
    total_enemy_dpt = sum(e["damage_per_turn"] for e in parsed)

    # Net damage taken per turn (after block)
    net_damage_per_turn = max(0, total_enemy_dpt - block_per_turn)

    # Turns until player dies (if only blocking, no kills)
    if net_damage_per_turn > 0:
        turns_to_die = player_hp // net_damage_per_turn
        if player_hp % net_damage_per_turn > 0:
            turns_to_die += 1
    else:
        turns_to_die = 999  # Effectively infinite - block exceeds damage

    # For each enemy, calculate turns to kill (focus fire) accounting for poison
    kill_data = []
    for e in parsed:
        hp = e["hp"]
        poison = e["poison"]
        turns = 0
        while hp > 0 and turns < 50:
            # Poison ticks at start of enemy turn
            if poison > 0:
                hp -= poison
                poison = max(0, poison - 1)
            if hp <= 0:
                turns += 1
                break
            # Player damage
            hp -= damage_per_turn
            turns += 1

        # Damage efficiency: how much total enemy damage is removed per turn spent killing this enemy
        if turns > 0 and e["damage_per_turn"] > 0:
            efficiency = e["damage_per_turn"] / turns  # DPT removed per turn invested
        elif turns > 0:
            efficiency = 0
        else:
            efficiency = 999

        kill_data.append({
            "name": e["name"],
            "hp": e["hp"],
            "turns_to_kill": turns,
            "damage_per_turn": e["damage_per_turn"],
            "poison": e["poison"],
            "kill_efficiency": round(efficiency, 2)
        })

    # Optimal target: highest kill efficiency (most DPT removed per turn spent)
    # Break ties by fewest turns to kill
    kill_data.sort(key=lambda x: (-x["kill_efficiency"], x["turns_to_kill"]))
    optimal_target = kill_data[0]["name"]
    turns_to_first_kill = kill_data[0]["turns_to_kill"]

    # Simulate focus-fire strategy: kill optimal target first
    # During those turns, how much damage does player take?
    damage_during_first_kill = net_damage_per_turn * turns_to_first_kill
    hp_after_first_kill = player_hp - damage_during_first_kill

    # Verdict
    if turns_to_die <= 1:
        verdict = "CRITICAL"
        advice = "Player dies next turn regardless. Use potions or pray."
    elif turns_to_first_kill >= turns_to_die:
        verdict = "OFFENSE_URGENT" 
        advice = f"Cannot kill anything before dying in {turns_to_die} turns. Must increase damage output (potions, all-in offense)."
    elif hp_after_first_kill <= 0:
        verdict = "OFFENSE_URGENT"
        advice = f"Will die before killing {optimal_target}. Need more offense or block."
    elif turns_to_first_kill >= turns_to_die * 0.7:
        verdict = "MANAGEABLE"
        advice = f"Tight but winnable. Focus {optimal_target} and block efficiently."
    else:
        verdict = "DEFENSE_OK"
        advice = f"Attrition war is favorable. Kill {optimal_target} first."

    return {
        "verdict": verdict,
        "advice": advice,
        "turns_to_die": turns_to_die,
        "turns_to_first_kill": turns_to_first_kill,
        "optimal_target": optimal_target,
        "net_damage_per_turn": net_damage_per_turn,
        "total_enemy_dpt": total_enemy_dpt,
        "hp_after_first_kill": hp_after_first_kill,
        "kill_order": [{"name": k["name"], "turns": k["turns_to_kill"], "efficiency": k["kill_efficiency"]} for k in kill_data]
    }


