SCHEMA = {
    "description": "Before playing a Power card (0 immediate block), checks whether spending energy on it is safe given incoming damage and HP. Returns GO (safe to play power) or NO-GO (save energy for block). Use BEFORE playing any power card when incoming damage is significant.",
    "properties": {
        "current_hp": {
            "type": "integer",
            "description": "Player's current HP"
        },
        "current_block": {
            "type": "integer",
            "description": "Block already on the player"
        },
        "incoming_damage": {
            "type": "integer",
            "description": "Total incoming damage this turn"
        },
        "energy_available": {
            "type": "integer",
            "description": "Total energy available this turn (before playing anything)"
        },
        "power_cost": {
            "type": "integer",
            "description": "Energy cost of the power card being considered"
        },
        "draw_cards_in_hand": {
            "type": "integer",
            "description": "Number of draw cards in hand that will be played (e.g., Acrobatics, Backflip). Each draw card might find a block card.",
            "default": 0
        },
        "block_cards_in_hand": {
            "type": "array",
            "items": {"type": "object"},
            "description": "List of block cards already in hand. Each: {name, block, cost}",
            "default": []
        },
        "avg_block_per_card": {
            "type": "integer",
            "description": "Average block from a typical block card in this deck (default 7)",
            "default": 7
        }
    },
    "required": ["current_hp", "current_block", "incoming_damage", "energy_available", "power_cost"]
}

def execute(current_hp, current_block, incoming_damage, energy_available, power_cost,
            draw_cards_in_hand=0, block_cards_in_hand=None, avg_block_per_card=7):
    if block_cards_in_hand is None:
        block_cards_in_hand = []

    # Calculate unblocked damage
    unblocked_damage = max(0, incoming_damage - current_block)

    # If no damage incoming, power is always fine
    if unblocked_damage == 0:
        return {"verdict": "GO", "reason": f"No unblocked damage (incoming {incoming_damage}, block {current_block}). Safe to play power."}

    # Calculate block from cards already in hand
    hand_block = 0
    hand_block_cost = 0
    for card in block_cards_in_hand:
        hand_block += card.get("block", 0)
        hand_block_cost += card.get("cost", 1)

    # Damage after playing all hand block cards
    remaining_damage_with_hand_block = max(0, unblocked_damage - hand_block)

    # Check if we're facing lethal even with all hand block cards
    facing_lethal = remaining_damage_with_hand_block >= current_hp

    # Energy after playing power
    energy_after_power = energy_available - power_cost
    # Energy needed for hand block cards
    energy_for_hand_block = hand_block_cost
    # Energy left for drawn block cards after power + hand block
    energy_for_draws_after_power = max(0, energy_after_power - energy_for_hand_block)

    # Energy if we skip power
    energy_without_power = energy_available
    energy_for_draws_without_power = max(0, energy_without_power - energy_for_hand_block)

    # Each draw card might find ~1 block card (conservative: 30% chance per card drawn, ~3 cards per draw card)
    # Potential extra block from draws if we have energy
    potential_block_with_power = energy_for_draws_after_power * avg_block_per_card
    potential_block_without_power = energy_for_draws_without_power * avg_block_per_card

    # Total potential block
    total_block_with_power = current_block + hand_block + potential_block_with_power
    total_block_without_power = current_block + hand_block + potential_block_without_power

    # Damage taken in each scenario
    damage_with_power = max(0, incoming_damage - total_block_with_power)
    damage_without_power = max(0, incoming_damage - total_block_without_power)

    survives_with_power = damage_with_power < current_hp
    survives_without_power = damage_without_power < current_hp

    # Extra block gained by skipping power
    extra_block_from_skip = potential_block_without_power - potential_block_with_power

    # Decision logic
    if not facing_lethal and unblocked_damage < current_hp * 0.5:
        # Not in danger - power is fine
        return {
            "verdict": "GO",
            "reason": f"Unblocked damage ({unblocked_damage}) is under 50% HP ({current_hp}). Power is safe.",
            "unblocked_damage": unblocked_damage,
            "hp_after": current_hp - max(0, unblocked_damage - hand_block)
        }

    if facing_lethal:
        if extra_block_from_skip > 0:
            return {
                "verdict": "NO-GO",
                "reason": f"LETHAL THREAT! Incoming {incoming_damage}, block {current_block} + hand block {hand_block} = {current_block + hand_block}. "
                          f"Unblocked: {remaining_damage_with_hand_block} vs {current_hp} HP. "
                          f"Skipping power saves {power_cost}E = up to {extra_block_from_skip} more block from drawn cards. "
                          f"Every energy MUST go to block.",
                "unblocked_damage": remaining_damage_with_hand_block,
                "extra_block_from_skip": extra_block_from_skip,
                "survives_with_power": survives_with_power,
                "survives_without_power": survives_without_power
            }
        else:
            return {
                "verdict": "GO",
                "reason": f"Facing lethal ({remaining_damage_with_hand_block} unblocked vs {current_hp} HP) but skipping power doesn't help — "
                          f"no extra energy would be available for block cards anyway.",
                "unblocked_damage": remaining_damage_with_hand_block
            }

    # High damage but not lethal
    hp_threshold = current_hp * 0.7
    if unblocked_damage > hp_threshold and extra_block_from_skip > 0:
        return {
            "verdict": "NO-GO",
            "reason": f"HIGH DAMAGE WARNING! Unblocked {unblocked_damage} is >{int(hp_threshold)} (70% of {current_hp} HP). "
                      f"Skipping power saves {power_cost}E for {extra_block_from_skip} potential block. Prioritize survival.",
            "unblocked_damage": unblocked_damage,
            "extra_block_from_skip": extra_block_from_skip,
            "damage_with_power": damage_with_power,
            "damage_without_power": damage_without_power
        }

    return {
        "verdict": "GO",
        "reason": f"Damage manageable. Unblocked: {unblocked_damage}, HP: {current_hp}. Power is acceptable.",
        "unblocked_damage": unblocked_damage,
        "damage_with_power": damage_with_power,
        "damage_without_power": damage_without_power
    }


