"""
Given your deck's average damage per turn and an enemy that scales its damage,
calculates whether you can kill it before it kills you. Returns turns to kill,
turns to die, and a GO/NO-GO verdict.

Use BEFORE entering elite fights with scaling enemies (Terror Eel, etc.)
and during combat to decide offense vs defense split.
"""

SCHEMA = {
    "description": "Checks if you can win a DPS race against a scaling enemy. Returns turns_to_kill, turns_to_die, and GO/NO-GO. Use before elite fights and during combat vs scaling enemies.",
    "properties": {
        "player_hp": {
            "type": "integer",
            "description": "Player's current HP"
        },
        "player_block_per_turn": {
            "type": "integer",
            "description": "Average block generated per turn"
        },
        "player_damage_per_turn": {
            "type": "integer",
            "description": "Average damage dealt per turn (accounting for block turns where you deal less)"
        },
        "enemy_hp": {
            "type": "integer",
            "description": "Enemy's current HP"
        },
        "enemy_base_damage": {
            "type": "integer",
            "description": "Enemy's starting attack damage"
        },
        "enemy_damage_scaling": {
            "type": "integer",
            "description": "How much enemy's attack increases each buff cycle (e.g., 6 for Terror Eel)"
        },
        "enemy_scales_every_n_turns": {
            "type": "integer",
            "description": "Enemy buffs every N turns (e.g., 2 for alternate-turn buffers)"
        },
        "weak_applied": {
            "type": "boolean",
            "description": "Whether you can reliably apply Weak each attack turn (reduces by 25%)"
        }
    },
    "required": ["player_hp", "player_block_per_turn", "player_damage_per_turn", 
                  "enemy_hp", "enemy_base_damage", "enemy_damage_scaling", "enemy_scales_every_n_turns"]
}

def execute(player_hp, player_block_per_turn, player_damage_per_turn, enemy_hp,
            enemy_base_damage, enemy_damage_scaling, enemy_scales_every_n_turns,
            weak_applied=False):
    import math

    hp = player_hp
    ehp = enemy_hp
    block = player_block_per_turn
    dmg = player_damage_per_turn

    current_enemy_damage = enemy_base_damage
    turns = 0
    damage_taken_total = 0
    damage_dealt_total = 0
    turn_log = []

    while hp > 0 and ehp > 0 and turns < 30:
        turns += 1

        # Enemy scales
        if turns > 1 and (turns - 1) % enemy_scales_every_n_turns == 0:
            current_enemy_damage += enemy_damage_scaling

        # Apply weak if available
        effective_enemy_damage = current_enemy_damage
        if weak_applied:
            effective_enemy_damage = math.floor(current_enemy_damage * 0.75)

        # Damage taken this turn
        net_damage = max(0, effective_enemy_damage - block)
        hp -= net_damage
        damage_taken_total += net_damage

        # Damage dealt this turn
        ehp -= dmg
        damage_dealt_total += dmg

        turn_log.append(f"T{turns}: deal {dmg}, take {net_damage} (enemy hits {effective_enemy_damage}), player HP={hp}, enemy HP={ehp}")

    turns_to_kill = None
    turns_to_die = None

    # Recalculate individually
    temp_ehp = enemy_hp
    for t in range(1, 31):
        temp_ehp -= dmg
        if temp_ehp <= 0:
            turns_to_kill = t
            break

    temp_hp = player_hp
    temp_dmg = enemy_base_damage
    for t in range(1, 31):
        if t > 1 and (t - 1) % enemy_scales_every_n_turns == 0:
            temp_dmg += enemy_damage_scaling
        eff = math.floor(temp_dmg * 0.75) if weak_applied else temp_dmg
        temp_hp -= max(0, eff - block)
        if temp_hp <= 0:
            turns_to_die = t
            break

    if turns_to_kill is None:
        turns_to_kill = 30
    if turns_to_die is None:
        turns_to_die = 30

    margin = turns_to_die - turns_to_kill

    if turns_to_kill > turns_to_die:
        verdict = "NO-GO"
        reason = f"Enemy kills you in {turns_to_die} turns but you need {turns_to_kill} turns to kill it. You lose by {-margin} turns."
    elif margin <= 1:
        verdict = "RISKY"
        reason = f"Barely win in {turns_to_kill} turns (die turn {turns_to_die}). One bad draw = death. Margin: {margin} turn(s)."
    else:
        verdict = "GO"
        reason = f"Kill in {turns_to_kill} turns, die in {turns_to_die}. Margin: {margin} turns."

    return {
        "verdict": verdict,
        "reason": reason,
        "turns_to_kill": turns_to_kill,
        "turns_to_die": turns_to_die,
        "margin": margin,
        "turn_log": turn_log[:5]  # First 5 turns for context
    }


