"""
Thorns Attack Tradeoff Calculator

Given attack cards in hand and enemy Thorns value, calculates the true
cost of each attack (damage dealt minus HP lost to Thorns). Returns
per-card analysis, total self-damage if all are played, and a
recommendation: which attacks are WORTH playing vs which to SKIP.

Rules:
- Each attack card played triggers Thorns once (flat damage back to player)
- Multi-hit attacks still only trigger Thorns ONCE per card play
- Net value = damage_to_enemy - thorns_damage_to_player
- Cards with net value <= 0 should almost NEVER be played
- Cards with positive net value but low efficiency (< 50% retained) are flagged
"""

SCHEMA = {
    "description": (
        "Given attack cards in hand and enemy Thorns value, calculates net damage "
        "(damage dealt minus HP lost) for each attack. Returns which attacks are "
        "worth playing and total self-damage cost. Use BEFORE playing any attack "
        "into a Thorns enemy."
    ),
    "properties": {
        "attack_cards": {
            "description": (
                "List of attack cards in hand. Each has 'name' (str), "
                "'damage' (int, total damage dealt to enemy), 'energy_cost' (int), "
                "and 'applies_poison' (int, poison stacks applied, 0 if none)."
            ),
            "items": {"type": "object"},
