def execute(attack_cards, thorns_value, player_hp, enemy_hp,
            poison_on_enemy=0, noxious_fumes_stacks=0):
    results = []
    total_self_damage = 0
    total_enemy_damage = 0
    worth_playing = []
    skip_list = []

    for card in attack_cards:
        name = card["name"]
        damage = card.get("damage", 0)
        energy = card.get("energy_cost", 1)
        poison = card.get("applies_poison", 0)

        net_damage = damage - thorns_value
        # Poison has ongoing value - estimate at 1.5x stacks as future damage
        poison_value = int(poison * 1.5)
        effective_net = net_damage + poison_value

        efficiency = round(net_damage / max(damage, 1) * 100)

        card_result = {
            "name": name,
            "damage_to_enemy": damage,
            "thorns_to_player": thorns_value,
            "net_damage": net_damage,
            "poison_applied": poison,
            "effective_net_with_poison": effective_net,
            "damage_efficiency": f"{efficiency}%",
            "energy_cost": energy,
        }

        if effective_net <= 0:
            card_result["verdict"] = "SKIP - net negative or zero"
            skip_list.append(name)
        elif efficiency < 50 and poison == 0:
            card_result["verdict"] = "MARGINAL - low efficiency, skip if alternatives exist"
            skip_list.append(name)
        else:
            card_result["verdict"] = "PLAY - worthwhile"
            worth_playing.append(name)

        total_self_damage += thorns_value
        total_enemy_damage += damage
        results.append(card_result)

    # Check if playing all attacks would be lethal
    survivable = player_hp > total_self_damage
    hp_after_all_attacks = player_hp - total_self_damage

    # Check if poison alone could eventually win (without needing attacks)
    poison_can_win = False
    if poison_on_enemy > 0 or noxious_fumes_stacks > 0:
        # Simulate poison kill
        sim_hp = enemy_hp
        sim_poison = poison_on_enemy
        for turn in range(30):
            sim_hp -= sim_poison
            if sim_hp <= 0:
                poison_can_win = True
                break
            sim_poison = max(0, sim_poison - 1) + noxious_fumes_stacks

    # Overall recommendation
    if len(skip_list) == len(attack_cards):
        overall = "SKIP ALL ATTACKS - pivot to poison/skills/powers"
    elif total_self_damage >= player_hp * 0.3:
        overall = f"DANGER - all attacks cost {total_self_damage} HP ({round(total_self_damage/player_hp*100)}% of HP). Play only high-value attacks."
    elif len(skip_list) > 0:
        overall = f"SELECTIVE - play {worth_playing}, skip {skip_list}"
    else:
        overall = "ALL WORTHWHILE - attacks have good net value despite Thorns"

    if poison_can_win:
        overall += " | POISON CAN WIN ALONE - consider blocking instead of attacking"

    return {
        "per_card_analysis": results,
        "total_self_damage_if_all_played": total_self_damage,
        "total_enemy_damage_if_all_played": total_enemy_damage,
        "net_total": total_enemy_damage - total_self_damage,
        "hp_after_all_attacks": hp_after_all_attacks,
        "player_survives_all": survivable,
        "poison_can_win_alone": poison_can_win,
        "worth_playing": worth_playing,
        "should_skip": skip_list,
        "overall_recommendation": overall
    }


