"""
Given Silent's current deck and a shop/event removal opportunity, returns priority order.
Curses/status cards MUST be removed before Strikes in Act 1.
"""

SCHEMA = {
    "deck": "List of card dicts with 'name' (str) and 'type' (str: attack/skill/power/curse/status)",
    "gold_available": "Current gold",
    "removal_cost": "Cost to remove a card (default 75 for shops)",
    "act": "Current act (1, 2, or 3)"
}

def execute(deck, gold_available, removal_cost=75, act=1):
    curses = [c for c in deck if c.get('type') == 'curse' or c.get('type') == 'status']
    strikes = [c for c in deck if c['name'] == 'Strike']
    defends = [c for c in deck if c['name'] == 'Defend']

    # Priority: curses > strikes > defends (never remove defends in Act 1)
    priority_list = []

    for curse in curses:
        priority_list.append({
            'card': curse['name'],
            'priority': 'CRITICAL',
            'reason': 'Curse/status cards clog draws and provide zero value'
        })

    if act >= 2 and len(strikes) > 2:
        for strike in strikes[:2]:
            priority_list.append({
                'card': 'Strike',
                'priority': 'HIGH',
                'reason': 'Strikes are weak in Act 2+'
            })

    can_afford = gold_available >= removal_cost

    if not priority_list:
        return {
            'verdict': 'SKIP',
            'reason': 'No high-priority removals available',
            'can_afford': can_afford
        }

    top_priority = priority_list[0]

    return {
        'verdict': 'REMOVE' if can_afford else 'CANNOT_AFFORD',
        'top_priority': top_priority,
        'all_priorities': priority_list,
        'can_afford': can_afford,
        'gold_needed': max(0, removal_cost - gold_available)
    }

