SCHEMA = {
    "description": "Before committing to an all-offense turn, checks whether planned damage kills the enemy. If not, compares HP cost of all-offense vs playing block cards instead. Returns KILL (go all-in), SPLIT (play some block), or BLOCK (full defense). Use BEFORE finalizing any plan where you spend all energy on offense with significant incoming damage.",
    "properties": {
        "planned_damage": {
            "type": "integer",
            "description": "Total damage your planned offensive cards will deal to the target enemy this turn"
        },
        "enemy_hp": {
            "type": "integer",
            "description": "Target enemy's current HP"
        },
        "incoming_damage": {
            "type": "integer",
            "description": "Total incoming damage from all enemies this turn"
        },
        "current_block": {
            "type": "integer",
            "description": "Block already on the player this turn"
        },
        "current_hp": {
            "type": "integer",
            "description": "Player's current HP"
        },
        "block_if_defensive": {
            "type": "integer",
            "description": "Total block you could generate if you spent ALL energy on block cards instead"
        },
        "block_if_split": {
            "type": "integer",
            "description": "Block you could generate if you replace 1 offensive card with 1 block card (approximate)",
            "default": 0
        },
        "damage_if_split": {
            "type": "integer",
            "description": "Damage you would deal if you replace 1 offensive card with 1 block card",
            "default": 0
        },
        "tungsten_rod": {
            "type": "boolean",
            "description": "Whether player has Tungsten Rod (reduces each damage instance by 1)",
            "default": False
        },
        "damage_instances": {
            "type": "integer",
            "description": "Number of separate damage instances incoming (for Tungsten Rod calc)",
            "default": 1
        }
    },
    "required": ["planned_damage", "enemy_hp", "incoming_damage", "current_block", "current_hp"]
}

def execute(planned_damage, enemy_hp, incoming_damage, current_block, current_hp,
            block_if_defensive=0, block_if_split=0, damage_if_split=0,
            tungsten_rod=False, damage_instances=1):
    """Decide whether to go all-offense, split offense/defense, or full block."""

    # Calculate Tungsten Rod reduction
    tr_reduction = damage_instances if tungsten_rod else 0
    effective_incoming = max(0, incoming_damage - current_block - tr_reduction)

    # Scenario 1: All-offense
    kills_enemy = planned_damage >= enemy_hp
    hp_after_offense = current_hp - effective_incoming
    survives_offense = hp_after_offense > 0

    # Scenario 2: Split (swap 1 attack for 1 block)
    if block_if_split > 0 or damage_if_split > 0:
        split_effective_incoming = max(0, incoming_damage - current_block - block_if_split - tr_reduction)
        hp_after_split = current_hp - split_effective_incoming
        split_kills = damage_if_split >= enemy_hp
        hp_saved_by_split = effective_incoming - split_effective_incoming
    else:
        hp_after_split = None
        split_kills = False
        hp_saved_by_split = 0

    # Scenario 3: Full defense
    if block_if_defensive > 0:
        def_effective_incoming = max(0, incoming_damage - current_block - block_if_defensive - tr_reduction)
        hp_after_defense = current_hp - def_effective_incoming
        hp_saved_by_defense = effective_incoming - def_effective_incoming
    else:
        hp_after_defense = None
        hp_saved_by_defense = 0

    # Decision logic
    if kills_enemy:
        verdict = "KILL"
        reason = f"All-offense kills enemy ({planned_damage} >= {enemy_hp} HP). Go all-in!"
    elif not survives_offense:
        verdict = "BLOCK"
        reason = (f"LETHAL: All-offense does NOT kill ({planned_damage} < {enemy_hp} HP) "
                 f"AND you die ({hp_after_offense} HP after {effective_incoming} unblocked damage). "
                 f"You MUST play block cards.")
    elif effective_incoming > current_hp * 0.5:
        # Taking more than 50% of HP without killing is very bad
        if hp_after_split is not None and hp_saved_by_split >= 5:
            verdict = "SPLIT"
            reason = (f"All-offense does NOT kill ({planned_damage} < {enemy_hp} HP) "
                     f"and costs {effective_incoming} HP ({hp_after_offense} remaining). "
                     f"Splitting saves {hp_saved_by_split} HP for only {planned_damage - damage_if_split} less damage.")
        else:
            verdict = "SPLIT"
            reason = (f"All-offense does NOT kill ({planned_damage} < {enemy_hp} HP) "
                     f"and costs {effective_incoming} HP (>{current_hp * 0.5:.0f}, over 50% of your HP). "
                     f"Mix in block cards to reduce HP loss.")
    elif effective_incoming > 15 and (enemy_hp - planned_damage) > 10:
        # Taking 15+ damage without killing and enemy still has 10+ HP
        verdict = "SPLIT"
        reason = (f"All-offense does NOT kill (enemy has {enemy_hp - planned_damage} HP left after {planned_damage} damage) "
                 f"and you take {effective_incoming} damage. Consider mixing in block.")
    else:
        verdict = "OFFENSE_OK"
        reason = (f"All-offense doesn't kill ({planned_damage} < {enemy_hp} HP) "
                 f"but damage taken is manageable ({effective_incoming} damage, {hp_after_offense} HP remaining).")

    result = {
        "verdict": verdict,
        "reason": reason,
        "kills_enemy": kills_enemy,
        "damage_dealt": planned_damage,
        "enemy_hp_remaining": max(0, enemy_hp - planned_damage),
        "unblocked_damage": effective_incoming,
        "hp_after_all_offense": hp_after_offense,
        "survives_all_offense": survives_offense,
    }

    if hp_after_split is not None:
        result["hp_after_split"] = hp_after_split
        result["hp_saved_by_split"] = hp_saved_by_split
        result["split_kills_enemy"] = split_kills

    if hp_after_defense is not None:
        result["hp_after_defense"] = hp_after_defense
        result["hp_saved_by_defense"] = hp_saved_by_defense

    return result


