    "description": "Before choosing an elite path on the map, checks if the deck has enough damage output to kill the elite in time. Returns GO (safe to fight elite) or NO-GO (avoid elite). Use at MAP decision time.",
    "properties": {
        "current_hp": {
            "description": "Player's current HP",
            "type": "integer"
        },
        "max_hp": {
            "description": "Player's max HP",
            "type": "integer"
        },
        "act": {
            "description": "Current act (1, 2, or 3)",
            "type": "integer"
        },
        "deck_size": {
            "description": "Total number of cards in deck",
            "type": "integer"
        },
        "attack_cards": {
            "description": "List of attack cards in deck. Each has 'name' (str), 'damage' (int, total damage per play), 'is_basic' (bool, True for Strike).",
            "type": "array",
            "items": {"type": "object"}
        },
        "has_scaling": {
            "description": "True if deck has scaling damage (Noxious Fumes, Envenom, Infinite Blades, etc.)",
            "type": "boolean"
        },
        "energy_per_turn": {
            "description": "Base energy per turn (default 3)",
            "type": "integer"
        }
    },
    "required": ["current_hp", "deck_size", "attack_cards", "act"]
}

def execute(current_hp, deck_size, attack_cards, act, max_hp=None, has_scaling=False, energy_per_turn=3):
    if max_hp is None:
        max_hp = current_hp

    # Elite HP estimates by act
    elite_hp = {1: 140, 2: 200, 3: 260}
    target_hp = elite_hp.get(act, 140)

    # Max safe turns before attrition kills you (elites deal ~15-25 avg damage/turn after block)
    # Estimate: you block ~60% of incoming, so net damage ~8-12/turn
    avg_net_damage_per_turn = {1: 8, 2: 12, 3: 15}
    net_dmg = avg_net_damage_per_turn.get(act, 10)
    max_safe_turns = max(1, current_hp // net_dmg)

    # Calculate average damage per turn from deck
    total_attack_damage = sum(c.get("damage", 0) for c in attack_cards)
    num_attacks = len(attack_cards)
    non_basic_attacks = [c for c in attack_cards if not c.get("is_basic", False)]
    non_basic_damage = sum(c.get("damage", 0) for c in non_basic_attacks)
    basic_attacks = [c for c in attack_cards if c.get("is_basic", False)]
    basic_count = len(basic_attacks)

    # Estimate cards drawn per turn (typically 5)
    cards_per_turn = 5
    if deck_size == 0:
        return {"verdict": "NO-GO", "reason": "Empty deck", "damage_per_turn": 0}

    # Fraction of hand that's attacks
    attack_fraction = num_attacks / deck_size
    attacks_per_hand = attack_fraction * cards_per_turn

    # Average energy spent on attacks per turn (~1.5-2 energy on attacks, rest on block)
    # Assume you spend about 50-60% of energy on attacks in an elite
    attack_energy_ratio = 0.5
    attack_energy = energy_per_turn * attack_energy_ratio

    # Average attack cost
    avg_attack_cost = 1.0  # most attacks cost 1
    attacks_played_per_turn = min(attacks_per_hand, attack_energy / avg_attack_cost)

    # Average damage per attack
    if num_attacks > 0:
        avg_damage_per_attack = total_attack_damage / num_attacks
    else:
        avg_damage_per_attack = 0

    damage_per_turn = attacks_played_per_turn * avg_damage_per_attack

    # Scaling bonus: add ~5 damage/turn average if scaling present
    if has_scaling:
        damage_per_turn += 5

    # Turns to kill
    if damage_per_turn > 0:
        turns_to_kill = target_hp / damage_per_turn
    else:
        turns_to_kill = 999

    # Calculate HP cost estimate
    estimated_hp_cost = int(turns_to_kill * net_dmg)

    # Decision factors
    reasons = []
    verdict = "GO"

    # HP gate
    hp_ratio = current_hp / max_hp
    if current_hp < 25:
        verdict = "NO-GO"
        reasons.append(f"HP too low ({current_hp}) — elites cost 25-35 HP typically")
    elif hp_ratio < 0.45:
        reasons.append(f"HP marginal ({current_hp}/{max_hp} = {hp_ratio:.0%})")

    # Damage gate
    if turns_to_kill > max_safe_turns:
        verdict = "NO-GO"
        reasons.append(f"Can't kill in time: {turns_to_kill:.1f} turns needed, survive {max_safe_turns} turns max")

    if turns_to_kill > 8:
        if verdict != "NO-GO":
            verdict = "NO-GO"
        reasons.append(f"Fight too long ({turns_to_kill:.1f} turns) — elite damage ramps")

    # Basic-heavy gate
    if num_attacks > 0 and basic_count / num_attacks > 0.7 and not has_scaling:
        verdict = "NO-GO"
        reasons.append(f"Attack pool is {basic_count}/{num_attacks} basics — insufficient burst damage")

    # Non-basic damage check
    if len(non_basic_attacks) < 2 and not has_scaling:
        if verdict != "NO-GO":
            verdict = "NO-GO"
        reasons.append(f"Only {len(non_basic_attacks)} non-basic attack(s) — need at least 2 or scaling")

    if not reasons:
        reasons.append("Deck has sufficient damage output and HP to handle elite")

    return {
        "verdict": verdict,
        "damage_per_turn_estimate": round(damage_per_turn, 1),
        "turns_to_kill_estimate": round(turns_to_kill, 1),
        "max_safe_turns": max_safe_turns,
        "estimated_hp_cost": estimated_hp_cost,
        "current_hp": current_hp,
        "non_basic_attacks": len(non_basic_attacks),
        "basic_attacks": basic_count,
        "has_scaling": has_scaling,
        "reasons": reasons
    }


