"""
Storm of Steel lethal calculator.
Given the current hand, which cards will be played BEFORE Storm of Steel,
and damage modifiers, calculates exact total damage including shivs generated.

Storm of Steel: Discard your hand. For each card discarded, add a Shiv to your hand.
Key insight: Cards played before Storm of Steel are NOT in hand when it resolves,
so they do NOT generate shivs. Storm of Steel itself is also not discarded.
"""

SCHEMA = {
    "description": "Given hand contents and play order before Storm of Steel, calculates exact shiv count and total damage. Use BEFORE any lethal attempt involving Storm of Steel.",
    "properties": {
        "hand_size": {
            "type": "integer",
            "description": "Total cards in hand at start of turn (including Storm of Steel, including any free shivs from Infinite Blades etc.)"
        },
        "cards_played_before_storm": {
            "type": "array",
            "items": {"type": "object"},
            "description": "List of cards played BEFORE Storm of Steel. Each has 'name' (str), 'damage' (int, total damage dealt), 'cost' (int, energy cost)."
        },
        "shiv_base_damage": {
            "type": "integer",
            "description": "Base damage per shiv (4 default, add +2 per Accuracy stack, add Strength)."
        },
        "enemy_hp": {
            "type": "integer",
            "description": "Current enemy HP."
        },
        "enemy_vulnerable": {
            "type": "boolean",
            "description": "Whether enemy is Vulnerable (1.5x damage). Default false."
        },
        "energy_available": {
            "type": "integer",
