"""
Before choosing an elite path on the map, checks whether the player has enough HP
to survive the fight. Returns GO/NO-GO with reasoning.

Elite fights typically deal 20-40 total damage even with good play.
At low HP percentages, the risk of death is too high.
"""

SCHEMA = {
    "description": "Before choosing a path with an elite, checks if current HP is safe enough to attempt the fight. Returns GO (safe to attempt) or NO-GO (avoid elite) with reasoning.",
    "properties": {
        "current_hp": {
            "type": "integer",
            "description": "Player's current HP"
        },
        "max_hp": {
            "type": "integer",
            "description": "Player's max HP"
        },
        "act": {
            "type": "integer",
            "description": "Current act (1, 2, or 3)"
        },
        "has_rest_before_elite": {
            "type": "boolean",
            "description": "Whether there's a rest site on the path before the elite (default False)"
        },
        "has_aoe_or_scaling": {
            "type": "boolean",
            "description": "Whether the deck has strong AoE, scaling damage, or poison (default True)"
        }
    },
    "required": ["current_hp", "max_hp", "act"]
}


def execute(current_hp, max_hp, act, has_rest_before_elite=False, has_aoe_or_scaling=True):
    hp_pct = current_hp / max_hp if max_hp > 0 else 0

    # Expected damage taken in elite fights by act
    expected_damage = {1: 20, 2: 30, 3: 40}
    elite_dmg = expected_damage.get(act, 30)

    # If there's a rest before the elite, account for healing
    effective_hp = current_hp
    if has_rest_before_elite:
        heal_amount = int(max_hp * 0.3)
        effective_hp = min(current_hp + heal_amount, max_hp)

    # Without AoE/scaling, fights last longer and take more damage
    if not has_aoe_or_scaling:
        elite_dmg = int(elite_dmg * 1.5)

    # Survival check: need HP to survive expected damage + buffer
    buffer = 10  # minimum HP to have after the fight
    hp_needed = elite_dmg + buffer
    survives = effective_hp >= hp_needed

    # HP percentage thresholds
    # Act 1: 40% minimum, Act 2: 50% minimum, Act 3: 50% minimum
    min_pct = {1: 0.40, 2: 0.50, 3: 0.50}
    pct_threshold = min_pct.get(act, 0.50)
    effective_pct = effective_hp / max_hp if max_hp > 0 else 0
    meets_pct = effective_pct >= pct_threshold

    go = survives and meets_pct

    reasons = []
    if not survives:
        reasons.append(f"HP {effective_hp} - expected damage {elite_dmg} = {effective_hp - elite_dmg} (need {buffer}+ remaining)")
    if not meets_pct:
        reasons.append(f"HP {effective_pct:.0%} below {pct_threshold:.0%} threshold for Act {act}")
    if not has_aoe_or_scaling:
        reasons.append(f"No AoE/scaling increases expected damage to {elite_dmg}")
    if has_rest_before_elite and effective_hp > current_hp:
        reasons.append(f"Rest site adds {effective_hp - current_hp} HP (effective HP: {effective_hp})")

    return {
        "decision": "GO" if go else "NO-GO",
        "current_hp": current_hp,
        "effective_hp": effective_hp,
        "max_hp": max_hp,
        "hp_pct": f"{hp_pct:.0%}",
        "effective_hp_pct": f"{effective_pct:.0%}",
        "expected_elite_damage": elite_dmg,
        "hp_after_fight": max(0, effective_hp - elite_dmg),
        "reasons": reasons,
        "recommendation": "AVOID elite path" if not go else "Elite path acceptable"
    }


