"""
Given block cards in hand and incoming damage, returns which block card to play first.
Prioritizes high-value cards (Survivor, Blur) over Defend when HP efficiency matters.
"""

APPLICABLE_STATES = ['monster', 'elite', 'boss']

SCHEMA = {
    "block_cards": {
        "type": "array",
        "description": "Block cards in hand. Each has 'name' (str) and 'base_block' (int).",
        "items": {"type": "object"}
    },
    "incoming_damage": {
        "type": "integer",
        "description": "Total incoming damage this turn"
    },
    "current_block": {
        "type": "integer",
        "description": "Block already on player",
        "default": 0
    },
    "energy_available": {
        "type": "integer",
        "description": "Energy available this turn"
    },
    "dexterity": {
        "type": "integer",
        "description": "Current Dexterity (can be negative)",
        "default": 0
    }
}

def execute(block_cards, incoming_damage, current_block=0, energy_available=3, dexterity=0):
    if not block_cards:
        return {"error": "No block cards in hand", "recommendation": "NONE"}

    # Calculate adjusted block for each card
    card_values = []
    for card in block_cards:
        name = card['name']
        base = card['base_block']
        adjusted = max(0, base + dexterity)

        # Energy cost (default 1 for most block cards)
        cost = card.get('cost', 1)
        if cost > energy_available:
            continue

        # Priority scoring: block per energy, with bonuses for special cards
        efficiency = adjusted / cost if cost > 0 else adjusted * 10

        # Bonuses for high-value Silent block cards
        if 'Survivor' in name:
            efficiency += 2  # Survivor is premium
        elif 'Blur' in name:
            efficiency += 3  # Blur carries block forward
        elif 'Backflip' in name:
            efficiency += 1  # Draw is valuable

        card_values.append({
            'name': name,
            'adjusted_block': adjusted,
            'cost': cost,
            'efficiency': efficiency
        })

    if not card_values:
        return {"error": "No playable block cards", "recommendation": "NONE"}

    # Sort by efficiency descending
    card_values.sort(key=lambda x: x['efficiency'], reverse=True)

    # Calculate deficit
    deficit = incoming_damage - current_block

    return {
        "recommended_card": card_values[0]['name'],
        "block_value": card_values[0]['adjusted_block'],
        "energy_cost": card_values[0]['cost'],
        "all_options": card_values,
        "deficit": deficit,
        "verdict": "PLAY_BLOCK" if deficit > 0 else "BLOCK_OPTIONAL"
    }

