"""
Before ending turn, verify we can survive and respond next turn.
Checks: Can we play cards next turn? Will our block hold? Do we have lethal?
"""

APPLICABLE_STATES = ['monster', 'elite', 'boss']

SCHEMA = {
    "current_hp": {"type": "integer", "description": "Player's current HP"},
    "current_block": {"type": "integer", "description": "Block remaining after this turn"},
    "incoming_damage_this_turn": {"type": "integer", "description": "Damage incoming this turn (should be 0 if ending turn safely)"},
    "incoming_damage_next_turn": {"type": "integer", "description": "Expected damage next turn"},
    "deck_size": {"type": "integer", "description": "Total cards in deck"},
    "cards_in_hand": {"type": "integer", "description": "Cards remaining in hand"},
    "energy_next_turn": {"type": "integer", "description": "Energy available next turn (usually 3)"},
    "lowest_card_cost_in_deck": {"type": "integer", "description": "Cheapest card cost in entire deck (0, 1, 2, etc)"}
}

def execute(current_hp, current_block, incoming_damage_this_turn, incoming_damage_next_turn, 
            deck_size, cards_in_hand, energy_next_turn, lowest_card_cost_in_deck):
    """
    Returns GO (safe to end turn) or NO-GO (must play more cards or die).
    """

    # Check 1: Are we dying THIS turn?
    if incoming_damage_this_turn > current_block:
        deficit = incoming_damage_this_turn - current_block
        if deficit >= current_hp:
            return {
                "verdict": "NO-GO",
                "reason": f"Dying THIS turn: {incoming_damage_this_turn} damage > {current_block} block, {deficit} unblocked >= {current_hp} HP",
                "recommendation": "Play block cards NOW"
            }

    # Check 2: Will we be able to play ANY card next turn?
    if lowest_card_cost_in_deck > energy_next_turn:
        return {
            "verdict": "NO-GO",
            "reason": f"Cannot play any card next turn: cheapest card costs {lowest_card_cost_in_deck}, only have {energy_next_turn} energy",
            "recommendation": "This should never happen with starter deck - check for corruption/status cards"
        }

    # Check 3: Block decay - will we survive next turn's hit with current block?
    # Block persists, but if next turn damage > current_block, we need to be able to play defense
    if incoming_damage_next_turn > current_block:
        unblocked_next = incoming_damage_next_turn - current_block
        if unblocked_next >= current_hp:
            # We're dying next turn unless we can block
            # Estimate: can we draw a block card? (rough heuristic)
            cards_drawn_next_turn = min(5, deck_size)  # Draw up to 5
            return {
                "verdict": "WARNING",
                "reason": f"Next turn: {incoming_damage_next_turn} damage, only {current_block} block persists, {unblocked_next} unblocked >= {current_hp} HP",
                "recommendation": f"Must draw and play block next turn. Drawing {cards_drawn_next_turn} cards.",
                "survival_requires_block": True
            }

    # Check 4: If we have cards in hand still, why are we ending turn?
    if cards_in_hand > 0:
        return {
            "verdict": "WARNING",
            "reason": f"Ending turn with {cards_in_hand} cards still in hand - verify they're all unplayable",
            "recommendation": "Double-check card costs vs remaining energy"
        }

    return {
        "verdict": "GO",
        "reason": "Safe to end turn: surviving this turn, can play cards next turn",
        "current_block_persists": current_block,
        "next_turn_damage": incoming_damage_next_turn
    }

