"""
Calculates actual damage dealt through Hardened Shell armor.
Hardened Shell reduces EACH instance of attack damage by a flat amount.
Multi-hit attacks are reduced per hit.
"""

APPLICABLE_STATES = ['monster', 'elite', 'boss']

SCHEMA = {
    "attack_cards": {
        "type": "list",
        "description": "Attack cards to play. Each has 'name' (str), 'base_damage' (int), 'hits' (int, default 1)",
        "required": True
    },
    "hardened_shell_value": {
        "type": "int",
        "description": "Hardened Shell armor value (damage reduction per hit)",
        "required": True
    },
    "strength": {
        "type": "int",
        "description": "Current Strength (default 0)",
        "required": False,
        "default": 0
    },
    "enemy_vulnerable": {
        "type": "bool",
        "description": "Enemy has Vulnerable (1.5x damage)",
        "required": False,
        "default": False
    }
}

def execute(attack_cards, hardened_shell_value, strength=0, enemy_vulnerable=False):
    total_damage = 0
    breakdown = []

    for card in attack_cards:
        name = card['name']
        base_damage = card['base_damage']
        hits = card.get('hits', 1)

        # Apply strength per hit
        damage_per_hit = base_damage + strength

        # Apply vulnerable
        if enemy_vulnerable:
            damage_per_hit = int(damage_per_hit * 1.5)

        # Apply Hardened Shell reduction per hit
        actual_damage_per_hit = max(0, damage_per_hit - hardened_shell_value)

        card_total = actual_damage_per_hit * hits
        total_damage += card_total

        breakdown.append({
            'card': name,
            'hits': hits,
            'damage_per_hit_before_armor': damage_per_hit,
            'damage_per_hit_after_armor': actual_damage_per_hit,
            'total_damage': card_total
        })

    return {
        'total_damage': total_damage,
        'breakdown': breakdown,
        'verdict': 'BLOCKED' if total_damage == 0 else 'OK'
    }

