When HP% is critically low, offense is NOT an option.
"""

SCHEMA = {
    "name": "hp_crisis_mode_check",
    "parameters": {
        "current_hp": {"type": "integer"},
        "max_hp": {"type": "integer"},
        "incoming_damage": {"type": "integer"},
        "block_available": {"type": "integer", "default": 0}
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(current_hp, max_hp, incoming_damage, block_available=0):
    hp_percent = (current_hp / max_hp) * 100
    unblocked = max(0, incoming_damage - block_available)
    hp_after = current_hp - unblocked

    # Crisis thresholds
    critical = hp_percent <= 25
    danger = hp_percent <= 40

    if critical:
        mode = "CRITICAL"
        strategy = "BLOCK EVERYTHING. No offense unless lethal."
    elif danger:
        mode = "DANGER"
        strategy = "Prioritize block. Offense only if fully safe."
    else:
        mode = "NORMAL"
        strategy = "Balance offense and defense."

    return {
        "hp_percent": round(hp_percent, 1),
        "mode": mode,
        "strategy": strategy,
        "will_die": hp_after <= 0,
        "hp_after_hit": hp_after,
        "verdict": "NO-GO: must block" if critical and incoming_damage > 0 else "GO"
    }

