"""
Checks if an AoE card is safe to play given current enemy states.
AoE cards that damage ALL enemies may have unintended effects when some enemies are dead.
"""

APPLICABLE_STATES = ['monster', 'elite', 'boss']

SCHEMA = {
    "aoe_card_name": "str: name of the AoE card being considered",
    "aoe_damage_per_enemy": "int: damage dealt to each enemy",
    "enemies": "list[dict]: each has 'name' (str), 'hp' (int), 'max_hp' (int), 'is_dead' (bool, default False)",
    "player_hp": "int: current player HP"
}

def execute(aoe_card_name, aoe_damage_per_enemy, enemies, player_hp):
    living = [e for e in enemies if not e.get('is_dead', False) and e['hp'] > 0]
    dead = [e for e in enemies if e.get('is_dead', False) or e['hp'] <= 0]

    if len(living) == 0:
        return {
            "safe": False,
            "verdict": "NO-GO",
            "reason": "No living enemies to damage",
            "living_count": 0,
            "dead_count": len(dead)
        }

    # Check if any living enemy would survive the AoE
    survivors = [e for e in living if e['hp'] > aoe_damage_per_enemy]

    # If all living enemies die, AoE is safe
    if len(survivors) == 0:
        return {
            "safe": True,
            "verdict": "GO",
            "reason": f"{aoe_card_name} kills all {len(living)} living enemies",
            "living_count": len(living),
            "dead_count": len(dead),
            "kills_all": True
        }

    # If some enemies are already dead and some would survive, this is risky
    # (game behavior with mixed dead/alive states can be unpredictable)
    if len(dead) > 0:
        return {
            "safe": False,
            "verdict": "NO-GO",
            "reason": f"{len(dead)} enemies already dead, {len(survivors)} would survive AoE. Unpredictable behavior - use single-target instead",
            "living_count": len(living),
            "dead_count": len(dead),
            "survivors": len(survivors)
        }

    # All enemies alive, some survive - this is normal AoE usage
    return {
        "safe": True,
        "verdict": "GO",
        "reason": f"{aoe_card_name} damages all {len(living)} living enemies",
        "living_count": len(living),
        "dead_count": len(dead),
        "survivors": len(survivors)
    }

