"""
Given current poison stacks, enemy HP, player HP, block capacity, and incoming damage,
returns whether poison will win the attrition race or if the player needs to switch to pure defense or add more poison.
"""

APPLICABLE_STATES = ['monster', 'elite', 'boss']

SCHEMA = {
    "name": "poison_attrition_race",
    "parameters": {
        "poison_stacks": {"type": "int", "description": "current poison on enemy"},
        "enemy_hp": {"type": "int", "description": "current enemy HP"},
        "player_hp": {"type": "int", "description": "current player HP"},
        "incoming_damage": {"type": "int", "description": "damage per turn from enemy"},
        "block_per_turn": {"type": "int", "description": "average block player can generate per turn"}
    }
}

def execute(poison_stacks, enemy_hp, player_hp, incoming_damage, block_per_turn):
    if poison_stacks == 0:
        return {
            "verdict": "NO_POISON",
            "reason": "No poison stacks active",
            "turns_to_enemy_death": 999,
            "turns_to_player_death": max(1, player_hp // max(1, incoming_damage - block_per_turn))
        }

    # Calculate turns for poison to kill enemy
    total_poison_damage = 0
    stacks = poison_stacks
    turns = 0
    while total_poison_damage < enemy_hp and turns < 50:
        turns += 1
        total_poison_damage += stacks
        stacks = max(0, stacks - 1)

    turns_to_enemy_death = turns if total_poison_damage >= enemy_hp else 999

    # Calculate turns until player dies
    net_damage_per_turn = max(0, incoming_damage - block_per_turn)
    if net_damage_per_turn == 0:
        turns_to_player_death = 999
    else:
        turns_to_player_death = (player_hp + net_damage_per_turn - 1) // net_damage_per_turn

    margin = turns_to_player_death - turns_to_enemy_death

    if turns_to_enemy_death < turns_to_player_death:
        return {
            "verdict": "POISON_WINS",
            "reason": f"Poison kills enemy in {turns_to_enemy_death} turns, player survives {turns_to_player_death} turns. Margin: {margin} turns",
            "turns_to_enemy_death": turns_to_enemy_death,
            "turns_to_player_death": turns_to_player_death,
            "margin": margin,
            "recommendation": "Focus on block, poison will finish the job"
        }
    elif turns_to_enemy_death == turns_to_player_death:
        return {
            "verdict": "TIED",
            "reason": f"Both die in {turns_to_enemy_death} turns. Need more poison or block",
            "turns_to_enemy_death": turns_to_enemy_death,
            "turns_to_player_death": turns_to_player_death,
            "margin": 0,
            "recommendation": "Add 1-2 more poison stacks or increase block"
        }
    else:
        deficit = turns_to_enemy_death - turns_to_player_death
        return {
            "verdict": "PLAYER_DIES_FIRST",
            "reason": f"Player dies in {turns_to_player_death} turns, enemy survives {turns_to_enemy_death} turns. Deficit: {deficit} turns",
            "turns_to_enemy_death": turns_to_enemy_death,
            "turns_to_player_death": turns_to_player_death,
            "margin": margin,
            "recommendation": f"CRITICAL: Need {deficit * 5} more poison stacks or switch to direct damage"
        }

