"""
Calculate how many turns until poison kills each enemy, and total poison damage remaining.
Helps Silent decide whether to spend cards finishing an enemy or let poison do the work.
"""

SCHEMA = {
    "name": "poison_lethal_calculator",
    "description": "For each enemy, calculate turns until poison kills them and whether additional damage is needed. Reports which enemies are 'poison dead' (will die from existing poison without further intervention).",
    "parameters": {
        "enemy_hp": {
            "type": "array",
            "items": {"type": "integer"},
            "description": "Current HP of each enemy"
        },
        "poison_stacks": {
            "type": "array",
            "items": {"type": "integer"},
            "description": "Current poison stacks on each enemy"
        },
        "num_enemies": {
            "type": "integer",
            "description": "Number of enemies"
        }
    },
    "required": ["enemy_hp", "poison_stacks", "num_enemies"]
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def poison_turns_to_kill(hp, poison):
    """Calculate how many end-of-turn ticks needed for poison to kill."""
    if poison <= 0 or hp <= 0:
        return float('inf') if hp > 0 else 0
    remaining_hp = hp
    ticks = 0
    current_poison = poison
    while remaining_hp > 0 and current_poison > 0:
        remaining_hp -= current_poison
        current_poison -= 1
        ticks += 1
    if remaining_hp > 0:
        return float('inf')  # Poison won't kill
    return ticks

def total_poison_damage(poison):
    """Total damage poison will deal over all remaining ticks: P + (P-1) + ... + 1 = P*(P+1)/2"""
    if poison <= 0:
        return 0
    return poison * (poison + 1) // 2

def execute(enemy_hp, poison_stacks, num_enemies):
    results = []
    for i in range(num_enemies):
        hp = enemy_hp[i] if i < len(enemy_hp) else 0
        poison = poison_stacks[i] if i < len(poison_stacks) else 0

        turns = poison_turns_to_kill(hp, poison)
        total_dmg = total_poison_damage(poison)
        hp_after_one_tick = max(0, hp - poison)
        poison_after_one_tick = max(0, poison - 1)
        dies_next_tick = poison >= hp and hp > 0
        poison_lethal = total_dmg >= hp  # Will poison eventually kill?
        extra_damage_needed = max(0, hp - total_dmg)  # How much direct damage still needed

        results.append({
            "enemy_index": i,
            "current_hp": hp,
            "poison": poison,
            "dies_next_tick": dies_next_tick,
            "poison_lethal": poison_lethal,
            "turns_to_die": turns if turns != float('inf') else -1,
            "total_poison_damage": total_dmg,
            "extra_damage_needed": extra_damage_needed,
            "hp_after_one_tick": hp_after_one_tick
        })

    summary_parts = []
    for r in results:
        if r["current_hp"] <= 0:
            summary_parts.append(f"Enemy {r['enemy_index']}: DEAD")
        elif r["dies_next_tick"]:
            summary_parts.append(f"Enemy {r['enemy_index']}: Dies next poison tick ({r['poison']} poison >= {r['current_hp']} HP)")
        elif r["poison_lethal"]:
            summary_parts.append(f"Enemy {r['enemy_index']}: Poison lethal in {r['turns_to_die']} ticks (ignore, save cards for others)")
        elif r["poison"] > 0:
            summary_parts.append(f"Enemy {r['enemy_index']}: Needs {r['extra_damage_needed']} more damage (poison covers {r['total_poison_damage']}/{r['current_hp']} HP)")
        else:
            summary_parts.append(f"Enemy {r['enemy_index']}: No poison, needs {r['current_hp']} damage")

    return {
        "enemies": results,
        "summary": " | ".join(summary_parts)
    }

