def execute(incoming_damage, current_hp, current_block, block_cards_in_hand, energy, dexterity):
    # Base block per Defend-type card is 5 in StS2, dexterity adds to each
    base_block_per_card = 5
    block_per_card = max(0, base_block_per_card + dexterity)

    # How many block cards can we actually play given energy (most cost 1)
    playable_block_cards = min(block_cards_in_hand, energy)

    # Total potential block
    max_available_block = current_block + (playable_block_cards * block_per_card)

    # Net damage after all possible block
    unblocked_damage = max(0, incoming_damage - max_available_block)

    # Block deficit: how much more block we'd need to fully block
    block_deficit = max(0, incoming_damage - max_available_block)

    # HP after taking unblocked damage
    hp_after_damage = current_hp - unblocked_damage

    # How many block cards needed to fully cover incoming damage
    remaining_after_current = max(0, incoming_damage - current_block)
    if block_per_card > 0:
        cards_needed_for_full_block = -(-remaining_after_current // block_per_card)  # ceiling division
    else:
        cards_needed_for_full_block = 999 if remaining_after_current > 0 else 0

    # Energy left after playing needed block cards
    energy_for_offense = max(0, energy - min(cards_needed_for_full_block, playable_block_cards))

    # Survival risk assessment
    lethal = hp_after_damage <= 0
    high_risk = hp_after_damage <= current_hp * 0.3 and unblocked_damage > 0

    # Recommendation
    if incoming_damage == 0:
        recommendation = "ALL_OFFENSE: No incoming damage, spend all energy on attacks"
    elif lethal:
        recommendation = f"LETHAL DANGER: Cannot fully block. Play ALL {playable_block_cards} block cards. Still take {unblocked_damage} unblockable damage. Consider potions."
    elif cards_needed_for_full_block <= playable_block_cards:
        recommendation = f"BLOCK_FIRST: Play {cards_needed_for_full_block} block card(s) to fully block, then use {energy_for_offense} energy for offense"
    elif high_risk:
        recommendation = f"HIGH_RISK: Play ALL {playable_block_cards} block cards. Still take {unblocked_damage} damage (HP drops to {hp_after_damage})"
    else:
        recommendation = f"PARTIAL_BLOCK: Play {playable_block_cards} block cards for {max_available_block - current_block} block. Take {unblocked_damage} damage (HP: {hp_after_damage})"

    return {
        "incoming_damage": incoming_damage,
        "current_block": current_block,
        "max_potential_block": max_available_block,
        "block_deficit": block_deficit,
        "unblocked_damage": unblocked_damage,
        "hp_after_damage": hp_after_damage,
        "lethal": lethal,
        "block_cards_needed": min(cards_needed_for_full_block, playable_block_cards),
        "energy_remaining_after_block": energy_for_offense,
        "recommendation": recommendation
    }

