APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(enemy_hp: int, poison_stacks: int) -> dict:
    """Simulate poison ticking each turn to determine lethality and time to kill.

    Poison mechanic: each turn, enemy takes [poison] damage, then poison decreases by 1.
    Total damage from P stacks = P*(P+1)/2
    """
    if poison_stacks <= 0:
        return {
            "turns_to_kill": -1,
            "total_poison_damage": 0,
            "is_lethal": False,
            "hp_deficit": enemy_hp,
            "recommendation": f"No poison on enemy. Need to apply poison or deal {enemy_hp} direct damage."
        }

    total_possible_damage = poison_stacks * (poison_stacks + 1) // 2

    if total_possible_damage < enemy_hp:
        return {
            "turns_to_kill": -1,
            "total_poison_damage": total_possible_damage,
            "is_lethal": False,
            "hp_deficit": enemy_hp - total_possible_damage,
            "recommendation": f"Poison NOT lethal. {total_possible_damage} total vs {enemy_hp} HP. Need {enemy_hp - total_possible_damage} more damage. Keep applying poison."
        }

    # Simulate to find exact turn of death
    remaining_hp = enemy_hp
    poison = poison_stacks
    turns = 0
    cumulative_damage = 0

    while poison > 0 and remaining_hp > 0:
        turns += 1
        remaining_hp -= poison
        cumulative_damage += poison
        poison -= 1

    return {
        "turns_to_kill": turns,
        "total_poison_damage": cumulative_damage,
        "is_lethal": True,
        "hp_deficit": 0,
        "overkill": abs(remaining_hp),
        "recommendation": f"Poison is LETHAL in {turns} turns with {abs(remaining_hp)} overkill. Switch to FULL DEFENSE - play only block cards."
    }

