    remaining_hp = hp
    turns = 0
    current_poison = poison
    total_damage = 0

    while current_poison > 0 and remaining_hp > 0:
        turns += 1
        remaining_hp -= current_poison
        total_damage += current_poison
        current_poison -= 1

    is_lethal = remaining_hp <= 0
    return {
        "lethal": is_lethal,
        "turns": turns if is_lethal else -1,
        "total_poison_damage": total_damage,
        "remaining_hp": max(0, remaining_hp),
        "damage_shortfall": max(0, remaining_hp) if not is_lethal else 0
    }

