    # Pad poison_stacks if shorter than enemy_hp
    while len(poison_stacks) < len(enemy_hp):
        poison_stacks.append(0)

    max_turns_needed = 0

    for i in range(len(enemy_hp)):
        hp = enemy_hp[i]
        poison = poison_stacks[i] if i < len(poison_stacks) else 0

        if hp <= 0:
            results.append({
                "enemy_index": i,
                "already_dead": True,
                "turns_to_kill": 0,
                "poison_is_lethal": True,
                "total_poison_damage": 0,
                "hp_shortfall": 0
            })
            continue

        if poison <= 0:
            results.append({
                "enemy_index": i,
                "already_dead": False,
                "turns_to_kill": -1,
                "poison_is_lethal": False,
                "total_poison_damage": 0,
                "hp_shortfall": hp
            })
            max_turns_needed = 999
            continue

        # Simulate poison ticking: each turn deals current poison then reduces by 1
        # Poison deals P, then P-1, then P-2, ... down to 1 = P*(P+1)/2 total
        remaining_hp = hp
        current_poison = poison
        turns = 0
        total_damage = 0

        while remaining_hp > 0 and current_poison > 0:
            turns += 1
            remaining_hp -= current_poison
            total_damage += current_poison
            current_poison -= 1

        is_lethal = remaining_hp <= 0
        # Total possible poison damage = poison*(poison+1)/2
        max_total_poison = poison * (poison + 1) // 2
        shortfall = max(0, hp - max_total_poison)

        if not is_lethal:
            turns = -1  # Won't kill

        results.append({
            "enemy_index": i,
            "already_dead": False,
            "turns_to_kill": turns,
            "poison_is_lethal": is_lethal,
            "total_poison_damage": max_total_poison,
            "hp_shortfall": shortfall
        })

        if is_lethal:
            max_turns_needed = max(max_turns_needed, turns)
        else:
            max_turns_needed = 999

    # Survival analysis: can we survive max_turns_needed turns?
    # Simple estimate: incoming_damage per turn * turns needed
    all_lethal = all(r["poison_is_lethal"] for r in results)
    estimated_damage_taken = incoming_damage * max_turns_needed if max_turns_needed < 999 else -1
    can_survive = current_hp > estimated_damage_taken if estimated_damage_taken >= 0 else False

    return {
        "enemies": results,
        "all_poison_lethal": all_lethal,
        "max_turns_to_kill": max_turns_needed if max_turns_needed < 999 else -1,
        "estimated_total_damage_taken": estimated_damage_taken,
