        "recommendation": (
            "DEFEND_ONLY: Poison is lethal, just survive!" if all_lethal and can_survive
            else "DEFEND_PRIORITY: Poison is lethal but survival is tight" if all_lethal and not can_survive
            else "STACK_MORE_POISON: Need more poison to kill" if not all_lethal
            else "MIXED: Evaluate per enemy"
        )
    }

