            "recommendation": "NO_DAMAGE",
            "detail": "No incoming damage this turn. Free to play powers/attacks."
        }

    block_per_card = 5 + dexterity

    # Option A: Pure block (spend all energy on block cards)
    playable_pure = min(energy, block_cards_in_hand)
    total_block_pure = current_block + playable_pure * block_per_card
    damage_pure = max(0, incoming_damage - total_block_pure)

    results = {
        "block_per_card": block_per_card,
        "incoming_damage": incoming_damage,
        "pure_block": {
            "total_block": total_block_pure,
            "cards_played": playable_pure,
            "energy_spent": playable_pure,
            "hp_lost": damage_pure
        }
    }

    # Option B: Weak costs 1 energy
    if energy >= 1:
        weakened_damage = int(incoming_damage * 0.75)
        remaining_energy_1 = energy - 1
        playable_weak1 = min(remaining_energy_1, block_cards_in_hand)
        total_block_weak1 = current_block + playable_weak1 * block_per_card
        damage_weak1 = max(0, weakened_damage - total_block_weak1)

        results["weak_1_energy"] = {
            "weakened_incoming": weakened_damage,
            "total_block": total_block_weak1,
            "block_cards_played": playable_weak1,
            "hp_lost": damage_weak1,
            "hp_saved_vs_pure_block": damage_pure - damage_weak1,
            "better_than_block": damage_weak1 < damage_pure
        }

    # Option C: Weak costs 2 energy
    if energy >= 2:
        weakened_damage = int(incoming_damage * 0.75)
        remaining_energy_2 = energy - 2
        playable_weak2 = min(remaining_energy_2, block_cards_in_hand)
        total_block_weak2 = current_block + playable_weak2 * block_per_card
        damage_weak2 = max(0, weakened_damage - total_block_weak2)

        results["weak_2_energy"] = {
            "weakened_incoming": weakened_damage,
            "total_block": total_block_weak2,
            "block_cards_played": playable_weak2,
            "hp_lost": damage_weak2,
            "hp_saved_vs_pure_block": damage_pure - damage_weak2,
            "better_than_block": damage_weak2 < damage_pure
        }

    # Determine best option
    options = [("pure_block", damage_pure)]
    if "weak_1_energy" in results:
        options.append(("weak_1_energy", results["weak_1_energy"]["hp_lost"]))
    if "weak_2_energy" in results:
        options.append(("weak_2_energy", results["weak_2_energy"]["hp_lost"]))

    best = min(options, key=lambda x: x[1])
    results["best_option"] = best[0]
    results["best_hp_lost"] = best[1]

    results["lethal_if_pure_block"] = damage_pure >= current_hp
    results["any_option_survives"] = best[1] < current_hp

    if best[0] == "pure_block":
        results["recommendation"] = "BLOCK IS BETTER. Pure block loses {} HP. Dex {} makes each block card worth {}.".format(damage_pure, dexterity, block_per_card)
    else:
        cost = 1 if best[0] == "weak_1_energy" else 2
        results["recommendation"] = "WEAK ({} energy) IS BETTER. Saves {} HP vs pure block.".format(cost, damage_pure - best[1])

    return results


