def _simulate_poison_kill(hp, poison):
    """Returns (turns_to_kill, is_lethal, remaining_hp). -1 turns means not lethal."""
    if hp <= 0:
        return (0, True, 0)
    if poison <= 0:
        return (-1, False, hp)
    remaining = hp
    p = poison
    turns = 0
    while remaining > 0 and p > 0:
        remaining -= p
        p -= 1
        turns += 1
    if remaining <= 0:
        return (turns, True, 0)
    else:
        return (-1, False, remaining)

def execute(current_hp, incoming_damage, enemy_hp, poison_stacks, energy, dexterity, block_cards_in_hand, current_block):
    # Handle edge cases
    if not enemy_hp:
        return {
            "enemies": [],
            "all_poison_lethal": True,
            "max_turns_to_kill": 0,
            "block_this_turn": current_block,
            "damage_this_turn": max(0, incoming_damage - current_block),
            "hp_after_this_turn": current_hp - max(0, incoming_damage - current_block),
            "can_survive_until_poison_kills": True,
            "recommendation": "NO_ENEMIES",
            "lethal_risk": False
        }

    # Pad poison_stacks if shorter than enemy_hp
    while len(poison_stacks) < len(enemy_hp):
        poison_stacks = list(poison_stacks) + [0]

    # Analyze each enemy
    enemy_results = []
    max_turns = 0
    all_lethal = True
    total_shortfall = 0

    for i in range(len(enemy_hp)):
        hp = enemy_hp[i]
        poison = poison_stacks[i] if i < len(poison_stacks) else 0
        turns, lethal, remaining = _simulate_poison_kill(hp, poison)

        entry = {
            "enemy_index": i,
            "hp": hp,
            "poison": poison,
            "turns_to_kill": turns,
            "poison_lethal": lethal
        }
        if not lethal:
            entry["damage_shortfall"] = remaining
            all_lethal = False
            total_shortfall += remaining
        else:
            max_turns = max(max_turns, turns)

        enemy_results.append(entry)

    # Block calculation for this turn
    base_block_per_card = 5 + dexterity
    affordable_cards = min(block_cards_in_hand, energy)
    max_block_this_turn = current_block + affordable_cards * base_block_per_card
    damage_this_turn = max(0, incoming_damage - max_block_this_turn)
    hp_after_turn = current_hp - damage_this_turn
    lethal_risk = hp_after_turn <= 0

    # Survival estimation over multiple turns
    can_survive = False
    if all_lethal and max_turns > 0:
        # Conservative estimate: assume 2 block cards per future turn, same incoming damage
        future_block_per_turn = 2 * base_block_per_card
        future_damage_per_turn = max(0, incoming_damage - future_block_per_turn)
        # Total damage over all turns needed
        total_estimated_damage = damage_this_turn + future_damage_per_turn * max(0, max_turns - 1)
        can_survive = current_hp > total_estimated_damage
    elif all_lethal and max_turns == 0:
        can_survive = True

    # Recommendation
    if lethal_risk:
        recommendation = "LETHAL_RISK_BLOCK_EVERYTHING"
    elif all_lethal and can_survive:
        recommendation = "DEFEND_AND_WAIT"
    elif all_lethal and not can_survive:
        recommendation = "POISON_LETHAL_BUT_NEED_MORE_BLOCK"
    elif total_shortfall > 0:
        recommendation = "ADD_MORE_POISON"
    else:
        recommendation = "MIXED_OFFENSE_DEFENSE"

    return {
        "enemies": enemy_results,
        "all_poison_lethal": all_lethal,
        "max_turns_to_kill": max_turns,
        "total_damage_shortfall": total_shortfall,
        "block_this_turn": max_block_this_turn,
        "damage_this_turn": damage_this_turn,
        "hp_after_this_turn": hp_after_turn,
        "can_survive_until_poison_kills": can_survive,
        "recommendation": recommendation,
        "lethal_risk": lethal_risk
    }

