    damage_this_turn = max(0, incoming_damage - max_block_this_turn)
    hp_after_turn = current_hp - damage_this_turn
    lethal_risk = hp_after_turn <= 0

    can_survive = False
    if all_lethal and max_turns > 0:
        future_block_per_turn = 2 * base_block_per_card
        future_damage_per_turn = max(0, incoming_damage - future_block_per_turn)
        total_estimated_damage = damage_this_turn + future_damage_per_turn * max(0, max_turns - 1)
        can_survive = current_hp > total_estimated_damage
    elif all_lethal and max_turns == 0:
        can_survive = True

    if lethal_risk:
        recommendation = "LETHAL_RISK_BLOCK_EVERYTHING"
    elif all_lethal and can_survive:
        recommendation = "DEFEND_AND_WAIT"
    elif all_lethal and not can_survive:
        recommendation = "POISON_LETHAL_BUT_NEED_MORE_BLOCK"
    elif total_shortfall > 0:
        recommendation = "ADD_MORE_POISON"
    else:
        recommendation = "MIXED_OFFENSE_DEFENSE"

    return {
        "enemies": enemy_results,
        "all_poison_lethal": all_lethal,
        "max_turns_to_kill": max_turns,
        "total_damage_shortfall": total_shortfall,
        "block_this_turn": max_block_this_turn,
        "damage_this_turn": damage_this_turn,
        "hp_after_this_turn": hp_after_turn,
        "can_survive_until_poison_kills": can_survive,
        "recommendation": recommendation,
        "lethal_risk": lethal_risk
    }

