    else:
        recommendation = "ADD_MORE_POISON: Current poison not lethal for all enemies"

    return {
        "per_enemy": per_enemy,
        "all_poison_lethal": all_lethal,
        "max_turns_to_kill": max_turns_needed,
        "achievable_block_this_turn": achievable_block,
        "net_damage_this_turn": net_damage,
        "hp_after_this_turn": hp_after,
        "lethal_this_turn": lethal_this_turn,
        "can_survive_until_poison_kills": can_survive,
        "recommendation": recommendation
    }


