        "energy": {"type": "integer", "minimum": 0},
        "hand_cards": {"type": "array", "items": {"type": "string"}},
        "hit_packets": {"type": "array", "items": {"type": "integer", "minimum": 0}}
    },
    "required": ["current_block", "current_hp", "dexterity", "energy", "hand_cards", "hit_packets"]
}

BLOCK_VALUES = {
    "defend": (5, 8),
    "survivor": (8, 11),
    "backflip": (5, 8),
    "blur": (5, 8),
    "cloak and dagger": (6, 8),
    "dash": (10, 13),
    "leg sweep": (11, 14),
}

COSTS = {
    "defend": 1,
    "survivor": 1,
    "backflip": 1,
    "blur": 1,
    "cloak and dagger": 1,
    "dash": 2,
    "leg sweep": 2,
    "footwork": 1,
    "piercing wail": 1,
    "neutralize": 0,
    "untouchable": 1,
}

DRAW_OR_FILTER = {"prepared", "acrobatics", "backflip"}


def _normalize(card):
    raw = card.strip().lower()
    upgraded = "+" in raw
    base = raw.replace("+", "")
    return base, upgraded


def _canonical_hand(cards):
    return tuple(sorted(cards))


def _packet_tuple(packets):
    return tuple(sorted((max(0, int(x)) for x in packets), reverse=True))


def _incoming_damage(packets, intangible):
    if intangible:
        return sum(1 for p in packets if p > 0)
    return sum(packets)


def _reduce_largest_packet_by_weak(packets):
    packets = list(packets)
    if not packets:
        return tuple()
    packets.sort(reverse=True)
    packets[0] = int(packets[0] * 0.75)
    return _packet_tuple(packets)


def _apply_card(card, energy, dexterity, block, packets, intangible):
    base, upgraded = _normalize(card)
    if base not in COSTS:
        return None
    cost = COSTS[base]
    if cost > energy:
        return None

    new_energy = energy - cost
    new_dex = dexterity
    new_block = block
    new_packets = packets
    new_intangible = intangible

    if base in BLOCK_VALUES:
        base_block = BLOCK_VALUES[base][1] if upgraded else BLOCK_VALUES[base][0]
        new_block += base_block + new_dex
        if base == "leg sweep":
            new_packets = _reduce_largest_packet_by_weak(new_packets)
    elif base == "footwork":
        new_dex += 3 if upgraded else 2
    elif base == "piercing wail":
        loss = 8 if upgraded else 6
        new_packets = _packet_tuple([max(0, p - loss) for p in new_packets])
    elif base == "neutralize":
        new_packets = _reduce_largest_packet_by_weak(new_packets)
    elif base == "untouchable":
        new_intangible = True
    else:
        return None

    return new_energy, new_dex, new_block, new_packets, new_intangible


def execute(current_block, current_hp, dexterity, energy, hand_cards, hit_packets):
    hand_cards = list(hand_cards)
    packets = _packet_tuple(hit_packets)
    modeled = []
    unmodeled = []
    draw_filter_present = []
    for c in hand_cards:
        base, _ = _normalize(c)
        if base in COSTS:
            modeled.append(c)
        else:
            unmodeled.append(c)
        if base in DRAW_OR_FILTER:
            draw_filter_present.append(c)

    @lru_cache(None)
    def solve(hand_tuple, cur_energy, cur_dex, cur_block, cur_packets, cur_intangible):
        incoming = _incoming_damage(cur_packets, cur_intangible)
        damage_taken = max(0, incoming - cur_block)
        best = (damage_taken, -cur_block, ())

        hand_list = list(hand_tuple)
        seen = set()
        for idx, card in enumerate(hand_list):
            if card in seen:
                continue
            seen.add(card)
            applied = _apply_card(card, cur_energy, cur_dex, cur_block, cur_packets, cur_intangible)
            if applied is None:
                continue
            next_energy, next_dex, next_block, next_packets, next_intangible = applied
            next_hand = hand_list[:idx] + hand_list[idx + 1 :]
            child = solve(
                _canonical_hand(next_hand),
                next_energy,
                next_dex,
                next_block,
                next_packets,
                next_intangible,
            )
            candidate = (child[0], child[1], (card,) + child[2])
            if candidate < best:
                best = candidate
        return best

    result = solve(_canonical_hand(modeled), energy, dexterity, current_block, packets, False)
    best_sequence = list(result[2])

    sim_energy = energy
    sim_dex = dexterity
    sim_block = current_block
    sim_packets = packets
    sim_intangible = False
    for card in best_sequence:
        sim_energy, sim_dex, sim_block, sim_packets, sim_intangible = _apply_card(
            card, sim_energy, sim_dex, sim_block, sim_packets, sim_intangible
        )

    final_incoming = _incoming_damage(sim_packets, sim_intangible)
    min_damage_taken = max(0, final_incoming - sim_block)
    survives = current_hp > min_damage_taken

    notes = []
    if draw_filter_present:
        notes.append("Draw/filter upside is not modeled; result is guaranteed from visible effects only.")
    if unmodeled:
        notes.append("Unmodeled cards ignored: " + ", ".join(unmodeled))
    if not best_sequence:
        notes.append("No modeled defensive line available with current energy.")

    return {
        "incoming_damage": _incoming_damage(packets, False),
        "final_incoming_after_best_line": final_incoming,
        "max_block_after_best_line": sim_block,
        "min_damage_taken": min_damage_taken,
        "survives": survives,
        "best_sequence": best_sequence,
        "energy_remaining": sim_energy,
        "modeled_cards": modeled,
        "unmodeled_cards": unmodeled,
        "notes": notes,
    }


