def _validate_lengths(names, costs, blocks):
    if len(names) != len(costs) or len(names) != len(blocks):
        raise ValueError("card_names, card_costs, and card_blocks must have the same length")


def _better(candidate, incumbent, costs):
    cand_block, cand_indices = candidate
    inc_block, inc_indices = incumbent
    if cand_block != inc_block:
        return cand_block > inc_block
    cand_cost = sum(costs[i] for i in cand_indices)
    inc_cost = sum(costs[i] for i in inc_indices)
    if cand_cost != inc_cost:
        return cand_cost < inc_cost
    if len(cand_indices) != len(inc_indices):
        return len(cand_indices) < len(inc_indices)
    return tuple(cand_indices) < tuple(inc_indices)


def execute(data):
    names = list(data["card_names"])
    costs = [int(x) for x in data["card_costs"]]
    blocks = [max(0, int(x)) for x in data["card_blocks"]]
    current_block = int(data["current_block"])
    current_hp = int(data["current_hp"])
    energy = int(data["energy"])
    incoming_damage = int(data["incoming_damage"])

    _validate_lengths(names, costs, blocks)
    if energy < 0:
        raise ValueError("energy must be non-negative")
    for c in costs:
        if c < 0:
            raise ValueError("card costs must be non-negative")

    best = [(-1, []) for _ in range(energy + 1)]
    best[0] = (0, [])

    for i in range(len(names)):
        cost = costs[i]
        block = blocks[i]
        for e in range(energy, cost - 1, -1):
            prev_block, prev_indices = best[e - cost]
            if prev_block < 0:
                continue
            candidate = (prev_block + block, prev_indices + [i])
            if best[e][0] < 0 or _better(candidate, best[e], costs):
                best[e] = candidate

    overall = (-1, [])
    overall_energy = 0
    for e in range(energy + 1):
        if best[e][0] < 0:
            continue
        if overall[0] < 0 or _better(best[e], overall, costs):
            overall = best[e]
            overall_energy = e

    max_additional_block, chosen_indices = overall
    if max_additional_block < 0:
        max_additional_block = 0
        chosen_indices = []
        overall_energy = 0

    chosen_names = [names[i] for i in chosen_indices]
    final_block = current_block + max_additional_block
    needed_block = max(0, incoming_damage - current_block)
    block_shortfall = max(0, incoming_damage - final_block)
    hp_loss = block_shortfall
    survives = hp_loss < current_hp
    lethal = hp_loss >= current_hp

    return {
        "needed_block": needed_block,
        "max_additional_block": max_additional_block,
        "energy_spent": overall_energy,
        "energy_remaining": max(0, energy - overall_energy),
        "chosen_indices": chosen_indices,
        "chosen_names": chosen_names,
        "final_block": final_block,
        "incoming_damage": incoming_damage,
        "hp_loss": hp_loss,
        "block_shortfall": block_shortfall,
        "survives": survives,
        "lethal": lethal
    }


