def _validate_lengths(names, costs, blocks):
    if len(names) != len(costs) or len(names) != len(blocks):
        raise ValueError("card_names, card_costs, and card_blocks must have the same length")


def _better(candidate, incumbent, costs):
    cand_block, cand_indices = candidate
    inc_block, inc_indices = incumbent
    if cand_block != inc_block:
        return cand_block > inc_block
    cand_cost = sum(costs[i] for i in cand_indices)
    inc_cost = sum(costs[i] for i in inc_indices)
    if cand_cost != inc_cost:
        return cand_cost < inc_cost
    if len(cand_indices) != len(inc_indices):
        return len(cand_indices) < len(inc_indices)
    return tuple(cand_indices) < tuple(inc_indices)


