def _best_block_subset(costs, values, energy):
    dp = [(0, []) for _ in range(energy + 1)]
    for idx, (cost, value) in enumerate(zip(costs, values)):
        for e in range(energy, cost - 1, -1):
            candidate_block = dp[e - cost][0] + value
            if candidate_block > dp[e][0]:
                dp[e] = (candidate_block, dp[e - cost][1] + [idx])
    best_energy = 0
    best_block = -1
    best_indices = []
    for e, (block, indices) in enumerate(dp):
        if block > best_block:
            best_block = block
            best_energy = e
            best_indices = indices
    return {
        "block": best_block,
        "energy_used": best_energy,
        "indices": best_indices,
    }


