def _best_block_subset(costs, values, energy):
    dp = [(0, []) for _ in range(energy + 1)]
    for idx, (cost, value) in enumerate(zip(costs, values)):
        for e in range(energy, cost - 1, -1):
            candidate_block = dp[e - cost][0] + value
            if candidate_block > dp[e][0]:
                dp[e] = (candidate_block, dp[e - cost][1] + [idx])
    best_energy = 0
    best_block = -1
    best_indices = []
    for e, (block, indices) in enumerate(dp):
        if block > best_block:
            best_block = block
            best_energy = e
            best_indices = indices
    return {
        "block": best_block,
        "energy_used": best_energy,
        "indices": best_indices,
    }


def execute(**input_data):
    energy = input_data["energy"]
    mandatory_cost = input_data["mandatory_cost"]
    mandatory_block = input_data["mandatory_block"]
    current_block = input_data["current_block"]
    current_hp = input_data["current_hp"]
    incoming_damage = input_data["incoming_damage"]
    costs = input_data["block_card_costs"]
    values = input_data["block_card_values"]

    if len(costs) != len(values):
        raise ValueError("block_card_costs and block_card_values must have the same length")

    best_without_mandatory = _best_block_subset(costs, values, energy)
    total_block_without_mandatory = current_block + best_without_mandatory["block"]
    net_damage_without_mandatory = max(0, incoming_damage - total_block_without_mandatory)
    hp_after_without_mandatory = current_hp - net_damage_without_mandatory
    survives_without_mandatory = hp_after_without_mandatory > 0

    mandatory_affordable = mandatory_cost <= energy
    if mandatory_affordable:
        remaining_energy = energy - mandatory_cost
        best_with_mandatory = _best_block_subset(costs, values, remaining_energy)
        total_block_with_mandatory = current_block + mandatory_block + best_with_mandatory["block"]
        net_damage_with_mandatory = max(0, incoming_damage - total_block_with_mandatory)
        hp_after_with_mandatory = current_hp - net_damage_with_mandatory
        survives_with_mandatory = hp_after_with_mandatory > 0
    else:
        remaining_energy = 0
        best_with_mandatory = {"block": 0, "energy_used": 0, "indices": []}
        total_block_with_mandatory = current_block
        net_damage_with_mandatory = max(0, incoming_damage - total_block_with_mandatory)
        hp_after_with_mandatory = current_hp - net_damage_with_mandatory
        survives_with_mandatory = False

    if not mandatory_affordable:
        recommendation = "mandatory_unaffordable"
    elif survives_with_mandatory:
        recommendation = "reserve_energy_for_mandatory_then_play_best_block"
    elif survives_without_mandatory:
        recommendation = "mandatory_play_causes_lethal_need_other_mitigation_or_kill"
    else:
        recommendation = "block_insufficient_even_with_best_line"

    return {
        "mandatory_affordable": mandatory_affordable,
        "remaining_energy_after_mandatory": remaining_energy,
        "best_optional_block_after_mandatory": best_with_mandatory["block"],
        "best_optional_indices_after_mandatory": best_with_mandatory["indices"],
        "best_optional_energy_after_mandatory": best_with_mandatory["energy_used"],
        "total_block_with_mandatory": total_block_with_mandatory,
        "net_damage_with_mandatory": net_damage_with_mandatory,
        "hp_after_with_mandatory": hp_after_with_mandatory,
        "survives_with_mandatory": survives_with_mandatory,
        "total_block_without_mandatory": total_block_without_mandatory,
        "net_damage_without_mandatory": net_damage_without_mandatory,
        "hp_after_without_mandatory": hp_after_without_mandatory,
        "survives_without_mandatory": survives_without_mandatory,
        "recommendation": recommendation,
    }


