def _validate_lengths(names, blocks, weaks, strength_down):
    n = len(names)
    return n == len(blocks) == len(weaks) == len(strength_down)



def _apply_modifiers_to_hit(hit, weak_turns, temp_strength_down):
    dmg = hit - temp_strength_down
    if dmg < 0:
        dmg = 0
    if weak_turns > 0:
        dmg = (dmg * 3) // 4
    return dmg



def execute(inputs):
    current_hp = inputs["current_hp"]
    start_block = inputs["start_block_next_turn"]
    next_turn_hits = inputs["next_turn_hits"]
    names = inputs["candidate_names"]
    blocks = inputs["candidate_block"]
    weaks = inputs["candidate_weak_turns"]
    strength_down = inputs["candidate_temp_strength_down"]

    if current_hp < 1:
        raise ValueError("current_hp must be at least 1")
    if start_block < 0:
        raise ValueError("start_block_next_turn must be non-negative")
    if not next_turn_hits:
        raise ValueError("next_turn_hits must be non-empty")
    if not names:
        raise ValueError("candidate_names must be non-empty")
    if not _validate_lengths(names, blocks, weaks, strength_down):
        raise ValueError("All candidate arrays must have the same length")

    base_incoming = sum(next_turn_hits)
    base_hp_loss = max(0, base_incoming - start_block)

    ranked = []
    for i in range(len(names)):
        modified_hits = [
            _apply_modifiers_to_hit(hit, weaks[i], strength_down[i])
            for hit in next_turn_hits
        ]
        incoming_after_modifiers = sum(modified_hits)
        total_block = start_block + blocks[i]
        hp_loss = max(0, incoming_after_modifiers - total_block)
        survives = hp_loss < current_hp
        safety_margin = current_hp - hp_loss
        prevented = base_hp_loss - hp_loss

        ranked.append({
            "name": names[i],
            "incoming_after_modifiers": incoming_after_modifiers,
            "total_block": total_block,
            "hp_loss": hp_loss,
            "damage_prevented_vs_no_retain": prevented,
            "survives": survives,
            "safety_margin": safety_margin,
            "modified_hits": modified_hits,
        })

    ranked.sort(
        key=lambda r: (
            1 if r["survives"] else 0,
            r["safety_margin"],
            r["damage_prevented_vs_no_retain"],
            r["total_block"],
            -r["incoming_after_modifiers"],
        ),
        reverse=True,
    )

    best = ranked[0]
    return {
        "base_incoming": base_incoming,
        "base_hp_loss_without_retain": base_hp_loss,
        "best_candidate": best["name"],
        "best_survives": best["survives"],
        "best_hp_loss": best["hp_loss"],
        "ranked_candidates": ranked,
    }


