    "description": "Ranks retain candidates by next-turn survival value against a known attack pattern. Compares carry-over block, Weak, and temporary Strength reduction.",
    "input_schema": {
        "type": "object",
        "properties": {
            "current_hp": {"type": "integer", "minimum": 1},
            "start_block_next_turn": {"type": "integer", "minimum": 0},
            "next_turn_hits": {
                "type": "array",
                "items": {"type": "integer", "minimum": 0},
                "minItems": 1
            },
            "candidate_names": {
                "type": "array",
                "items": {"type": "string"},
                "minItems": 1
            },
            "candidate_block": {
                "type": "array",
                "items": {"type": "integer", "minimum": 0},
                "minItems": 1
            },
            "candidate_weak_turns": {
                "type": "array",
                "items": {"type": "integer", "minimum": 0},
                "minItems": 1
            },
            "candidate_temp_strength_down": {
                "type": "array",
                "items": {"type": "integer", "minimum": 0},
                "minItems": 1
            }
        },
        "required": [
            "current_hp",
            "start_block_next_turn",
            "next_turn_hits",
            "candidate_names",
            "candidate_block",
            "candidate_weak_turns",
            "candidate_temp_strength_down"
        ]
    }
}


def _same_length(a, b, c, d):
    return len(a) == len(b) == len(c) == len(d)


def _modified_hit(hit, weak_turns, temp_strength_down):
    dmg = hit - temp_strength_down
    if dmg < 0:
        dmg = 0
    if weak_turns > 0:
        dmg = (dmg * 3) // 4
    return dmg


def execute(current_hp, start_block_next_turn, next_turn_hits, candidate_names, candidate_block, candidate_weak_turns, candidate_temp_strength_down):
    if current_hp < 1:
        raise ValueError("current_hp must be at least 1")
    if start_block_next_turn < 0:
        raise ValueError("start_block_next_turn must be non-negative")
    if len(next_turn_hits) == 0:
        raise ValueError("next_turn_hits must be non-empty")
    if len(candidate_names) == 0:
        raise ValueError("candidate_names must be non-empty")
    if not _same_length(candidate_names, candidate_block, candidate_weak_turns, candidate_temp_strength_down):
        raise ValueError("candidate arrays must have the same length")

    base_incoming = sum(next_turn_hits)
    base_hp_loss = max(0, base_incoming - start_block_next_turn)

    ranked = []
    for i in range(len(candidate_names)):
        modified_hits = []
        for hit in next_turn_hits:
            modified_hits.append(_modified_hit(hit, candidate_weak_turns[i], candidate_temp_strength_down[i]))
        incoming_after_modifiers = sum(modified_hits)
        total_block = start_block_next_turn + candidate_block[i]
        hp_loss = max(0, incoming_after_modifiers - total_block)
        survives = hp_loss < current_hp
        ranked.append({
            "name": candidate_names[i],
            "incoming_after_modifiers": incoming_after_modifiers,
            "total_block": total_block,
            "hp_loss": hp_loss,
            "damage_prevented_vs_none": base_hp_loss - hp_loss,
            "survives": survives,
            "safety_margin": current_hp - hp_loss,
            "modified_hits": modified_hits,
        })

    ranked.sort(key=lambda r: (1 if r["survives"] else 0, r["safety_margin"], r["damage_prevented_vs_none"], r["total_block"]), reverse=True)
    best = ranked[0]
    return {
        "base_incoming": base_incoming,
        "base_hp_loss_without_candidate": base_hp_loss,
        "best_candidate": best["name"],
        "best_survives": best["survives"],
        "best_hp_loss": best["hp_loss"],
        "ranked_candidates": ranked,
    }


