        "costs": {"type": "array", "items": {"type": "integer", "minimum": 0}},
        "block_values": {"type": "array", "items": {"type": "integer", "minimum": 0}},
        "current_block": {"type": "integer", "minimum": 0},
        "current_hp": {"type": "integer", "minimum": 0},
        "energy": {"type": "integer", "minimum": 0},
        "incoming_damage": {"type": "integer", "minimum": 0}
    },
    "required": [
        "card_names",
        "costs",
        "block_values",
        "current_block",
        "current_hp",
        "energy",
        "incoming_damage"
    ]
}


def _validate(inputs):
    names = inputs["card_names"]
    costs = inputs["costs"]
    blocks = inputs["block_values"]
    if len(names) != len(costs) or len(names) != len(blocks):
        raise ValueError("card_names, costs, and block_values must have identical lengths")



def execute(inputs):
    _validate(inputs)
    names = inputs["card_names"]
    costs = inputs["costs"]
    blocks = inputs["block_values"]
    current_block = inputs["current_block"]
    current_hp = inputs["current_hp"]
    energy = inputs["energy"]
    incoming = inputs["incoming_damage"]

    best_by_energy = {0: (0, ())}

    for idx, (cost, block) in enumerate(zip(costs, blocks)):
        updated = dict(best_by_energy)
        for spent, (total_block, picks) in best_by_energy.items():
            new_spent = spent + cost
            if new_spent > energy:
                continue
            candidate = (total_block + block, picks + (idx,))
            previous = updated.get(new_spent)
            if previous is None:
                updated[new_spent] = candidate
            else:
                prev_block, prev_picks = previous
                cand_block, cand_picks = candidate
                if cand_block > prev_block or (cand_block == prev_block and len(cand_picks) < len(prev_picks)):
                    updated[new_spent] = candidate
        best_by_energy = updated

    best_spent = 0
    best_total_added = 0
    best_picks = ()
    for spent, (added_block, picks) in best_by_energy.items():
        if added_block > best_total_added:
            best_spent = spent
            best_total_added = added_block
            best_picks = picks
        elif added_block == best_total_added:
            if spent < best_spent or (spent == best_spent and len(picks) < len(best_picks)):
                best_spent = spent
                best_picks = picks

    chosen_cards = [names[i] for i in best_picks]
    final_block = current_block + best_total_added
    hp_loss = incoming - final_block
    if hp_loss < 0:
        hp_loss = 0
    hp_after = current_hp - hp_loss

    need_to_live = incoming - current_block - (current_hp - 1)
    if need_to_live < 0:
        need_to_live = 0
    need_for_full_cover = incoming - current_block
    if need_for_full_cover < 0:
        need_for_full_cover = 0

    return {
        "selected_cards": chosen_cards,
        "energy_spent": best_spent,
        "spare_energy": energy - best_spent,
        "max_additional_block": best_total_added,
        "total_block": final_block,
        "incoming_damage": incoming,
        "hp_loss": hp_loss,
        "hp_after": hp_after,
        "survives": hp_after > 0,
        "full_cover": final_block >= incoming,
        "additional_block_needed_to_live": need_to_live,
        "additional_block_needed_for_full_cover": need_for_full_cover
    }


