    "properties": {
        "current_hp": {"type": "integer", "minimum": 0},
        "starting_block": {"type": "integer", "minimum": 0},
        "enemy_damage_per_hit": {
            "type": "array",
            "items": {"type": "integer", "minimum": 0}
        },
        "enemy_hit_counts": {
            "type": "array",
            "items": {"type": "integer", "minimum": 1}
        },
        "flat_block": {"type": "integer", "minimum": 0},
        "strength_down": {"type": "integer", "minimum": 0}
    },
    "required": [
        "current_hp",
        "starting_block",
        "enemy_damage_per_hit",
        "enemy_hit_counts",
        "flat_block",
        "strength_down"
    ]
}


def execute(current_hp, starting_block, enemy_damage_per_hit, enemy_hit_counts, flat_block, strength_down):
    if len(enemy_damage_per_hit) != len(enemy_hit_counts):
        raise ValueError("enemy_damage_per_hit and enemy_hit_counts must have the same length")

    total_incoming = 0
    total_after_strength = 0
    reductions = []

    for dmg, hits in zip(enemy_damage_per_hit, enemy_hit_counts):
        incoming = dmg * hits
        reduced_per_hit = max(0, dmg - strength_down)
        after_strength = reduced_per_hit * hits
        prevented = incoming - after_strength
        total_incoming += incoming
        total_after_strength += after_strength
        reductions.append(prevented)

    net_with_block = max(0, total_incoming - starting_block - flat_block)
    net_with_strength = max(0, total_after_strength - starting_block)

    if net_with_strength < net_with_block:
        better = "strength_down"
    elif net_with_block < net_with_strength:
        better = "flat_block"
    else:
        better = "equal"

    return {
        "total_incoming": total_incoming,
        "total_after_strength_down": total_after_strength,
        "damage_prevented_by_strength_down": total_incoming - total_after_strength,
        "damage_prevented_by_flat_block": min(flat_block, max(0, total_incoming - starting_block)),
        "per_enemy_strength_reduction": reductions,
        "net_damage_with_flat_block": net_with_block,
        "net_damage_with_strength_down": net_with_strength,
        "survives_with_flat_block": current_hp > net_with_block,
        "survives_with_strength_down": current_hp > net_with_strength,
        "better_defense": better
    }


