CONDITIONAL_DEFENSE = {
    "escape plan",
    "escape plan+",
    "piercing wail",
    "piercing wail+",
    "neutralize",
    "neutralize+"
}


def _norm(card_name):
    return card_name.strip().lower()


def _effective_block(base_block, total_dex):
    return max(0, base_block + total_dex)


def _best_block_with_energy(block_cards, energy_left, total_dex):
    dp = {0: (0, [])}
    for card in block_cards:
        cost = card["cost"]
        gained = _effective_block(card["block"], total_dex)
        next_dp = dict(dp)
        for spent, (blk, chosen) in dp.items():
            new_spent = spent + cost
            if new_spent > energy_left:
                continue
            new_block = blk + gained
            prev = next_dp.get(new_spent)
            if prev is None or new_block > prev[0]:
                next_dp[new_spent] = (new_block, chosen + [card["name"]])
        dp = next_dp
    best_spent = 0
    best_block = 0
    best_cards = []
    for spent, (blk, chosen) in dp.items():
        if blk > best_block or (blk == best_block and spent < best_spent):
            best_spent = spent
            best_block = blk
            best_cards = chosen
    return best_block, best_spent, best_cards


def execute(hand, dexterity, current_block, energy, incoming_damage):
    dex_cards = []
    block_cards = []
    ignored_cards = []
    conditional_cards = []

    for raw in hand:
        name = _norm(raw)
        data = CARD_DATA.get(name)
        if data is None:
            if name in CONDITIONAL_DEFENSE:
                conditional_cards.append(raw)
            else:
                ignored_cards.append(raw)
            continue
        entry = {"name": raw, **data}
        if data["kind"] == "dex":
            dex_cards.append(entry)
        else:
            block_cards.append(entry)

    best = None
    n = len(dex_cards)
    for mask in range(1 << n):
        chosen_dex = []
        spent_on_dex = 0
        added_dex = 0
        for i in range(n):
            if mask & (1 << i):
                chosen_dex.append(dex_cards[i]["name"])
                spent_on_dex += dex_cards[i]["cost"]
                added_dex += dex_cards[i]["dex"]
        if spent_on_dex > energy:
            continue

        total_dex = dexterity + added_dex
        energy_left = energy - spent_on_dex
        block_gained, spent_on_block, chosen_block = _best_block_with_energy(block_cards, energy_left, total_dex)
        total_block = current_block + block_gained
        net_damage = max(0, incoming_damage - total_block)
        state = {
            "max_guaranteed_block": total_block,
            "additional_block_from_hand": block_gained,
            "net_damage": net_damage,
            "full_block_available": net_damage == 0,
            "energy_spent": spent_on_dex + spent_on_block,
            "chosen_dex_cards": chosen_dex,
            "chosen_block_cards": chosen_block,
            "recommended_sequence": chosen_dex + chosen_block,
            "conditional_defense_not_counted": conditional_cards,
            "ignored_cards": ignored_cards,
            "assumptions": [
                "Counts only guaranteed current-turn block from known Silent block cards in hand.",
                "Dexterity setup is played before block cards.",
                "Conditional effects like Escape Plan and enemy-dependent mitigation like Piercing Wail are excluded from guaranteed block."
            ]
        }
        if best is None:
            best = state
            continue
        if state["net_damage"] < best["net_damage"]:
            best = state
        elif state["net_damage"] == best["net_damage"]:
            if state["max_guaranteed_block"] > best["max_guaranteed_block"]:
                best = state
            elif state["max_guaranteed_block"] == best["max_guaranteed_block"] and state["energy_spent"] < best["energy_spent"]:
                best = state

    if best is None:
        best = {
            "max_guaranteed_block": current_block,
            "additional_block_from_hand": 0,
            "net_damage": max(0, incoming_damage - current_block),
            "full_block_available": incoming_damage <= current_block,
            "energy_spent": 0,
            "chosen_dex_cards": [],
            "chosen_block_cards": [],
            "recommended_sequence": [],
            "conditional_defense_not_counted": conditional_cards,
            "ignored_cards": ignored_cards,
            "assumptions": [
                "No recognized guaranteed block line found in hand.",
                "Conditional effects like Escape Plan and enemy-dependent mitigation like Piercing Wail are excluded from guaranteed block."
            ]
        }

    return best


