from typing import Any, Dict, List

SCHEMA = {
    "name": "poison_survival_analysis",
    "description": "Calculates turns until poison kills each enemy (no new poison assumed) and whether player can survive that long. Helps decide: keep stacking poison vs switch to pure defense. Shows damage shortfall if poison isn't lethal.",
    "parameters": {
        "type": "object",
        "properties": {
            "current_hp": {"type": "integer", "description": "Player current HP"},
            "incoming_damage": {"type": "integer", "description": "Total incoming damage this turn"},
            "enemy_hp": {"type": "array", "items": {"type": "integer"}, "description": "Current HP of each enemy"},
            "poison_stacks": {"type": "array", "items": {"type": "integer"}, "description": "Current poison stacks on each enemy"}
        },
        "required": ["current_hp", "incoming_damage", "enemy_hp", "poison_stacks"]
    }
}

APPLICABLE_STATES = ["monster", "elite", "boss"]

def execute(current_hp: int, incoming_damage: int, enemy_hp: List[int], poison_stacks: List[int]) -> Dict[str, Any]:
    if not enemy_hp or not poison_stacks or len(enemy_hp) != len(poison_stacks):
        return {"error": "enemy_hp and poison_stacks must be same length lists"}

    results = []
    max_turns = 0
    all_lethal = True

    for hp, poison in zip(enemy_hp, poison_stacks):
        if hp <= 0:
            results.append({"lethal": True, "turns_to_kill": 0, "shortfall": 0})
            continue

        if poison == 0:
            results.append({"lethal": False, "turns_to_kill": -1, "shortfall": hp})
            all_lethal = False
            continue

        turns = 0
        current_p = poison
        remaining_hp = hp

        while remaining_hp > 0 and current_p > 0:
            turns += 1
            remaining_hp -= current_p
            current_p -= 1

        if remaining_hp <= 0:
            results.append({"lethal": True, "turns_to_kill": turns, "shortfall": 0})
            max_turns = max(max_turns, turns)
        else:
            results.append({"lethal": False, "turns_to_kill": -1, "shortfall": remaining_hp})
            all_lethal = False

    survival_turns = max(1, current_hp // max(1, incoming_damage)) if incoming_damage > 0 else 999

    recommendation = ""
    if not all_lethal:
        recommendation = "Poison is NOT lethal. You MUST apply more poison or play attacks to win."
    elif max_turns == 1:
        recommendation = "Lethal this turn! Ignore long-term block, just survive incoming damage."
    elif survival_turns < max_turns:
        recommendation = f"DANGER: Poison is lethal in {max_turns} turns, but you die in {survival_turns} turns at current damage rate. PURE DEFENSE REQUIRED."
    else:
        recommendation = f"SAFE: Poison is lethal in {max_turns} turns. Focus entirely on blocking to preserve HP."

    return {
        "enemy_status": results,
        "all_lethal_without_more_poison": all_lethal,
        "max_turns_to_win": max_turns if all_lethal else -1,
        "estimated_survival_turns": survival_turns,
        "recommendation": recommendation
    }

