def _card_info(card_name):
    return CARD_DATA.get(card_name, {"cost": 99})


def _is_known(card_name):
    return card_name in CARD_DATA


def _block_from_card(card_name, dexterity, temp_dex):
    info = _card_info(card_name)
    base = info.get("block", 0)
    if base <= 0:
        return 0
    total_dex = dexterity + temp_dex
    return max(0, base + total_dex)


def _apply_weak(incoming_damage, weak_turns):
    if weak_turns <= 0:
        return incoming_damage
    return (incoming_damage * 3) // 4


def _line_result(cards, current_block, energy, dexterity, incoming_damage):
    temp_dex = 0
    perm_dex = dexterity
    spent = 0
    block = current_block
    weak_turns = 0
    attack_down = 0
    played = []

    for card in cards:
        info = _card_info(card)
        cost = info.get("cost", 99)
        if spent + cost > energy:
            return None
        spent += cost
        played.append(card)
        if "temp_dex" in info:
            temp_dex += info["temp_dex"]
        if "dex" in info:
            perm_dex += info["dex"]
        if "block" in info:
            block += _block_from_card(card, perm_dex, temp_dex)
        if "weak" in info:
            weak_turns = max(weak_turns, info["weak"])
        if "attack_down" in info:
            attack_down += info["attack_down"]

    adjusted_damage = _apply_weak(incoming_damage, weak_turns)
    adjusted_damage = max(0, adjusted_damage - attack_down)
    net_damage = max(0, adjusted_damage - block)
    return {
        "played": played,
        "energy_spent": spent,
        "block": block,
        "adjusted_incoming": adjusted_damage,
        "net_damage": net_damage
    }


def _best_line(hand, current_block, energy, dexterity, incoming_damage, forbid_conversion):
    legal_cards = []
    for card in hand:
        if not _is_known(card):
            continue
        if forbid_conversion and _card_info(card).get("conversion"):
            continue
        legal_cards.append(card)

    best = {
        "played": [],
        "energy_spent": 0,
        "block": current_block,
        "adjusted_incoming": incoming_damage,
        "net_damage": max(0, incoming_damage - current_block)
    }

    n = len(legal_cards)
    for r in range(1, n + 1):
        for combo in combinations(range(n), r):
            cards = [legal_cards[i] for i in combo]
            result = _line_result(cards, current_block, energy, dexterity, incoming_damage)
            if result is None:
                continue
            if result["net_damage"] < best["net_damage"]:
                best = result
            elif result["net_damage"] == best["net_damage"] and result["block"] > best["block"]:
                best = result
    return best


def execute(current_hp, current_block, energy, dexterity, incoming_damage, hand):
    baseline = _best_line(hand, current_block, energy, dexterity, incoming_damage, True)
    has_conversion = any(_card_info(card).get("conversion") for card in hand if _is_known(card))
    recommendation = "no_conversion_card_in_hand"
    hp_loss_risk = baseline["net_damage"] > 0

    if has_conversion:
        recommendation = "safe_to_convert_only_if_post-conversion line still full-blocks"
        if baseline["net_damage"] > 0:
            recommendation = "do_not_convert_hand; spend energy on mitigation first"
        elif baseline["energy_spent"] < energy:
            recommendation = "full-block first; only convert after mitigation if spare energy remains"
        else:
            recommendation = "use conversion only after confirming retained mitigation is unnecessary"

    return {
        "best_no_conversion_line": baseline["played"],
        "best_no_conversion_net_damage": baseline["net_damage"],
        "best_no_conversion_block": baseline["block"],
        "hp_loss_risk_without_perfect_sequencing": hp_loss_risk,
        "has_hand_conversion_card": has_conversion,
        "recommendation": recommendation,
        "survives_best_no_conversion_line": current_hp > baseline["net_damage"]
    }


