def _info(card):
    return CARD_DATA.get(card, {"cost": 99})


def _block(card, perm_dex, temp_dex):
    base = _info(card).get("block", 0)
    if base <= 0:
        return 0
    return max(0, base + perm_dex + temp_dex)


def _weak_damage(damage, weak_turns):
    if weak_turns > 0:
        return (damage * 3) // 4
    return damage


def _line(cards, current_block, energy, dexterity, incoming_damage):
    spent = 0
    block = current_block
    perm_dex = dexterity
    temp_dex = 0
    weak_turns = 0
    attack_down = 0
    played = []
    for card in cards:
        info = _info(card)
        cost = info.get("cost", 99)
        if spent + cost > energy:
            return None
        spent += cost
        played.append(card)
        if "temp_dex" in info:
            temp_dex += info["temp_dex"]
        if "dex" in info:
            perm_dex += info["dex"]
        block += _block(card, perm_dex, temp_dex)
        weak_turns = max(weak_turns, info.get("weak", 0))
        attack_down += info.get("attack_down", 0)
    adjusted = max(0, _weak_damage(incoming_damage, weak_turns) - attack_down)
    return {"played": played, "energy_spent": spent, "block": block, "net_damage": max(0, adjusted - block)}


def _best(hand, current_block, energy, dexterity, incoming_damage):
    cards = []
    for card in hand:
        info = _info(card)
        if info.get("cost", 99) < 99 and not info.get("conversion", False):
            cards.append(card)
    best = {"played": [], "energy_spent": 0, "block": current_block, "net_damage": max(0, incoming_damage - current_block)}
    for size in range(1, len(cards) + 1):
        for indexes in combinations(range(len(cards)), size):
            result = _line([cards[i] for i in indexes], current_block, energy, dexterity, incoming_damage)
            if result is None:
                continue
            if result["net_damage"] < best["net_damage"]:
                best = result
            elif result["net_damage"] == best["net_damage"] and result["block"] > best["block"]:
                best = result
    return best


def execute(current_hp=0, current_block=0, energy=0, dexterity=0, incoming_damage=0, hand=None):
    if hand is None:
        hand = []
    best = _best(hand, current_block, energy, dexterity, incoming_damage)
    has_conversion = False
    for card in hand:
        if _info(card).get("conversion", False):
            has_conversion = True
    if not has_conversion:
        recommendation = "no hand-conversion card in hand"
    elif best["net_damage"] > 0:
        recommendation = "do_not_convert_hand; use best mitigation line first"
    elif best["energy_spent"] < energy:
        recommendation = "full-block first; convert only with spare energy after mitigation"
    else:
        recommendation = "conversion is risky; mitigation consumes all energy"
    return {
        "best_no_conversion_line": best["played"],
        "best_no_conversion_net_damage": best["net_damage"],
        "best_no_conversion_block": best["block"],
        "has_hand_conversion_card": has_conversion,
        "hp_loss_risk": best["net_damage"] > 0,
        "recommendation": recommendation,
        "survives_best_no_conversion_line": current_hp > best["net_damage"]
    }

