import math

SCHEMA = {
    "name": "silent_hp_guardrail",
    "description": "Computes a conservative Silent HP reserve, a max safe optional HP-loss budget, and whether to favor resting or safer pathing. Useful before HP-loss events, campfires, and risky map branches.",
    "input_schema": {
        "type": "object",
        "properties": {
            "current_hp": {"type": "integer"},
            "max_hp": {"type": "integer"},
            "floor": {"type": "integer"},
            "act": {"type": "integer"}
        },
        "required": ["current_hp", "max_hp", "floor", "act"]
    }
}

APPLICABLE_STATES = ["map", "rest_site", "event"]


def _floor_in_act(floor, act):
    start_floor = 1 + 17 * (act - 1)
    floor_in_act = floor - start_floor + 1
    if floor_in_act < 1:
        return 1
    if floor_in_act > 17:
        return 17
    return floor_in_act


def _reserve_hp(max_hp, act, floor_in_act):
    if act <= 1:
        if floor_in_act <= 5:
            return max(14, int(math.ceil(max_hp * 0.24)))
        if floor_in_act <= 10:
            return max(18, int(math.ceil(max_hp * 0.32)))
        if floor_in_act <= 14:
            return max(26, int(math.ceil(max_hp * 0.45)))
        return max(30, int(math.ceil(max_hp * 0.52)))

    if act == 2:
        if floor_in_act <= 5:
            return max(18, int(math.ceil(max_hp * 0.32)))
        if floor_in_act <= 10:
            return max(22, int(math.ceil(max_hp * 0.40)))
        if floor_in_act <= 14:
            return max(26, int(math.ceil(max_hp * 0.46)))
        return max(30, int(math.ceil(max_hp * 0.54)))

    if floor_in_act <= 5:
        return max(22, int(math.ceil(max_hp * 0.38)))
    if floor_in_act <= 10:
        return max(26, int(math.ceil(max_hp * 0.46)))
    if floor_in_act <= 14:
        return max(30, int(math.ceil(max_hp * 0.52)))
    return max(34, int(math.ceil(max_hp * 0.60)))


def execute(current_hp, max_hp, floor, act):
    floor_in_act = _floor_in_act(floor, act)
    reserve_hp = _reserve_hp(max_hp, act, floor_in_act)
    buffer_hp = current_hp - reserve_hp
    max_safe_optional_hp_loss = max(0, buffer_hp // 2)

    if buffer_hp < 0:
        risk_tier = "critical"
    elif floor_in_act >= 11 and buffer_hp < 12:
        risk_tier = "tight"
    elif buffer_hp < 8:
        risk_tier = "tight"
    else:
        risk_tier = "comfortable"

    avoid_optional_hp_spend = max_safe_optional_hp_loss == 0
    prefer_rest_over_smith = buffer_hp < 4 or (floor_in_act >= 12 and buffer_hp < 8)
    avoid_optional_elites = buffer_hp < 6

    if risk_tier == "critical":
        recommendation = "Preserve HP immediately: avoid optional HP loss, avoid elites, and rest at the next campfire."
    elif risk_tier == "tight":
        recommendation = "Take the safer line: optional HP trades must stay within the spend budget and upgrades are secondary to preserving HP."
    else:
        recommendation = "HP buffer is healthy; you can upgrade or accept a modest HP trade if it stays within the spend budget."

    return {
        "floor_in_act": floor_in_act,
        "reserve_hp": reserve_hp,
        "buffer_hp": buffer_hp,
        "max_safe_optional_hp_loss": max_safe_optional_hp_loss,
        "risk_tier": risk_tier,
        "avoid_optional_hp_spend": avoid_optional_hp_spend,
        "prefer_rest_over_smith": prefer_rest_over_smith,
        "avoid_optional_elites": avoid_optional_elites,
        "recommendation": recommendation
    }


